Application::Application() :
    event_group_(xEventGroupCreate()),
    state_machine_([this](DeviceState state) { 
        auto display = Board::GetInstance().GetDisplay();
        display->UpdateStatusBar(true);
    }),
    aec_mode_(CONFIG_ENABLE_DEVICE_AEC ? kAecOnDeviceSide : 
              (CONFIG_ENABLE_SERVER_AEC ? kAecOnServerSide : kAecOff)),
    listening_mode_(kListeningModeAutoStop),
    play_popup_on_listening_(false),
    aborted_(false),
    has_server_time_(false),
    assets_version_checked_(false),
    activation_task_handle_(nullptr),
    clock_timer_handle_(nullptr),
    clock_ticks_(0)
{
    // Create the clock timer
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = [](void* arg) {
        Application* app = static_cast<Application*>(arg);
        xEventGroupSetBits(app->event_group_, MAIN_EVENT_CLOCK_TICK);
    };
    timer_args.arg = this;
    timer_args.name = "clock_timer";

    esp_timer_create(&timer_args, &clock_timer_handle_);
}

void Application::Initialize()
{
    auto &board = Board::GetInstance();
    SetDeviceState(kDeviceStateStarting);

    // Initialize core system components
    auto display = board.GetDisplay();
    auto codec = board.GetAudioCodec();

    // Start the audio service
    audio_service_.Start();

    // Initialize the display
    display->Initialize();

    // Start the clock timer
    esp_timer_start_periodic(clock_timer_handle_, 1000000); // 1 second interval

    // Register MCP server tools
    McpServer::GetInstance().RegisterTools();

    // Define all main events
    const EventBits_t ALL_EVENTS = 
        MAIN_EVENT_WAKE_WORD_DETECTED |
        MAIN_EVENT_VAD_CHANGE |
        MAIN_EVENT_CLOCK_TICK |
        MAIN_EVENT_ERROR |
        MAIN_EVENT_NETWORK_CONNECTED |
        MAIN_EVENT_NETWORK_DISCONNECTED |
        MAIN_EVENT_TOGGLE_CHAT |
        MAIN_EVENT_START_LISTENING |
        MAIN_EVENT_STOP_LISTENING |
        MAIN_EVENT_ACTIVATION_DONE |
        MAIN_EVENT_STATE_CHANGED |
        MAIN_EVENT_SEND_AUDIO |
        MAIN_EVENT_SCHEDULE;

    while (true)
    {
        auto bits = xEventGroupWaitBits(event_group_, ALL_EVENTS, pdTRUE, pdFALSE, portMAX_DELAY);

        if (bits & MAIN_EVENT_ERROR)
        {
            SetDeviceState(kDeviceStateIdle);
            Alert(Lang::Strings::ERROR, last_error_message_.c_str(), "circle_xmark", Lang::Sounds::OGG_EXCLAMATION);
        }

        if (bits & MAIN_EVENT_NETWORK_CONNECTED)
        {
            HandleNetworkConnectedEvent();
        }

        if (bits & MAIN_EVENT_NETWORK_DISCONNECTED)
        {
            HandleNetworkDisconnectedEvent();
        }

        if (bits & MAIN_EVENT_ACTIVATION_DONE)
        {
            HandleActivationDoneEvent();
        }

        if (bits & MAIN_EVENT_STATE_CHANGED)
        {
            HandleStateChangedEvent();
        }

        if (bits & MAIN_EVENT_TOGGLE_CHAT)
        {
            HandleToggleChatEvent();
        }

        if (bits & MAIN_EVENT_START_LISTENING)
        {
            HandleStartListeningEvent();
        }

        if (bits & MAIN_EVENT_STOP_LISTENING)
        {
            HandleStopListeningEvent();
        }

        if (bits & MAIN_EVENT_SEND_AUDIO)
        {
            while (auto packet = audio_service_.PopPacketFromSendQueue())
            {
                if (protocol_ && !protocol_->SendAudio(std::move(packet)))
                {
                    break;
                }
            }
        }

        if (bits & MAIN_EVENT_WAKE_WORD_DETECTED)
        {
            HandleWakeWordDetectedEvent();
        }

        if (bits & MAIN_EVENT_VAD_CHANGE)
        {
            if (GetDeviceState() == kDeviceStateListening)
            {
                auto led = Board::GetInstance().GetLed();
                led->OnStateChanged();
            }
        }

        if (bits & MAIN_EVENT_SCHEDULE)
        {
            std::unique_lock<std::mutex> lock(mutex_);
            auto tasks = std::move(main_tasks_);
            lock.unlock();
            for (auto &task : tasks)
            {
                task();
            }
        }

        if (bits & MAIN_EVENT_CLOCK_TICK)
        {
            clock_ticks_++;
            auto display = Board::GetInstance().GetDisplay();
            display->UpdateStatusBar();

            // Print debug info every 10 seconds
            if (clock_ticks_ % 10 == 0)
            {
                SystemInfo::PrintHeapStats();
            }
        }
    }
}

void Application::Run()
{
    const EventBits_t ALL_EVENTS =
        MAIN_EVENT_SCHEDULE |
        MAIN_EVENT_SEND_AUDIO |
        MAIN_EVENT_WAKE_WORD_DETECTED |
        MAIN_EVENT_VAD_CHANGE |
        MAIN_EVENT_CLOCK_TICK |
        MAIN_EVENT_STATE_CHANGED |
        MAIN_EVENT_NETWORK_CONNECTED |
        MAIN_EVENT_NETWORK_DISCONNECTED |
        MAIN_EVENT_ACTIVATION_DONE |
        MAIN_EVENT_TOGGLE_CHAT |
        MAIN_EVENT_START_LISTENING |
        MAIN_EVENT_STOP_LISTENING |
        MAIN_EVENT_ERROR;

    while (true)
    {
        EventBits_t events = xEventGroupWaitBits(
            event_group_,
            ALL_EVENTS,
            pdTRUE,  // Clear bits on exit
            pdFALSE, // Wait for any bit
            portMAX_DELAY);

        // Handle scheduled tasks first
        if (events & MAIN_EVENT_SCHEDULE)
        {
            std::lock_guard<std::mutex> lock(mutex_);
            while (!main_tasks_.empty())
            {
                auto task = std::move(main_tasks_.front());
                main_tasks_.pop_front();
                lock.unlock();
                task();
                lock.lock();
            }
        }

        // Handle activation done event
        if (events & MAIN_EVENT_ACTIVATION_DONE)
        {
            HandleActivationDoneEvent();
        }

        // Handle network events
        if (events & MAIN_EVENT_NETWORK_CONNECTED)
        {
            // Network connected logic could be added here if needed
        }

        if (events & MAIN_EVENT_NETWORK_DISCONNECTED)
        {
            HandleNetworkDisconnectedEvent();
        }

        // Handle state change events
        if (events & MAIN_EVENT_STATE_CHANGED)
        {
            HandleStateChangedEvent();
        }

        // Handle user interaction events
        if (events & MAIN_EVENT_TOGGLE_CHAT)
        {
            HandleToggleChatEvent();
        }

        if (events & MAIN_EVENT_START_LISTENING)
        {
            HandleStartListeningEvent();
        }

        if (events & MAIN_EVENT_STOP_LISTENING)
        {
            HandleStopListeningEvent();
        }

        // Handle audio service events
        if (events & MAIN_EVENT_WAKE_WORD_DETECTED)
        {
            HandleWakeWordDetectedEvent();
        }

        if (events & MAIN_EVENT_VAD_CHANGE)
        {
            // VAD change handling could be implemented here if needed
        }

        if (events & MAIN_EVENT_SEND_AUDIO)
        {
            // Send audio data if channel is open and we have data
            if (protocol_ && protocol_->IsAudioChannelOpened())
            {
                auto packet = audio_service_.PopEncodedPacket();
                if (packet)
                {
                    protocol_->SendAudio(std::move(packet));
                }
            }
        }

        // Handle clock tick for periodic updates
        if (events & MAIN_EVENT_CLOCK_TICK)
        {
            auto display = Board::GetInstance().GetDisplay();
            display->UpdateStatusBar();

            // Increment clock ticks and handle idle timeout
            clock_ticks_++;

            // Handle idle timeout logic if needed
            DeviceState state = GetDeviceState();
            if (state == kDeviceStateIdle && clock_ticks_ >= 60) // 60 seconds idle
            {
                // Could implement screen saver or other idle behavior here
                clock_ticks_ = 0;
            }
        }

        // Handle error events
        if (events & MAIN_EVENT_ERROR)
        {
            if (!last_error_message_.empty())
            {
                ESP_LOGE(TAG, "Network error: %s", last_error_message_.c_str());
                Alert(Lang::Strings::ERROR, last_error_message_.c_str(), "circle_xmark", Lang::Sounds::OGG_EXCLAMATION);
                last_error_message_.clear();
            }
        }
    }
}

void Application::HandleNetworkConnectedEvent()
{
    ESP_LOGI(TAG, "Network connected");
    auto state = GetDeviceState();

    if (state == kDeviceStateStarting || state == kDeviceStateWifiConfiguring)
    {
        // Network is ready, start activation
        SetDeviceState(kDeviceStateActivating);
        if (activation_task_handle_ != nullptr)
        {
            ESP_LOGW(TAG, "Activation task already running");
            return;
        }

        xTaskCreate([](void *arg)
                    {
            Application* app = static_cast<Application*>(arg);
            app->ActivationTask();
            app->activation_task_handle_ = nullptr;
            vTaskDelete(NULL); }, "activation", 4096 * 2, this, 2, &activation_task_handle_);
    }

    // Update the status bar immediately to show the network state
    auto display = Board::GetInstance().GetDisplay();
    display->UpdateStatusBar(true);
}

void Application::HandleActivationDoneEvent()
{
    ESP_LOGI(TAG, "Activation done");

    // Check if we have a valid OTA object
    if (!ota_)
    {
        ESP_LOGE(TAG, "OTA object not initialized");
        SetDeviceState(kDeviceStateIdle);
        return;
    }

    // Initialize the communication protocol
    InitializeProtocol();

    // Set device to idle state after successful activation
    SetDeviceState(kDeviceStateIdle);

    // Dismiss any alert messages and show standby status
    DismissAlert();

    // Get display instance to update UI
    auto display = Board::GetInstance().GetDisplay();
    display->SetStatus(Lang::Strings::STANDBY);
    display->SetEmotion("neutral");
    display->SetChatMessage("system", "");

    // Enable wake word detection now that activation is complete
    audio_service_.EnableWakeWordDetection(true);

    // Update the status bar to reflect the new state
    display->UpdateStatusBar(true);
}

void Application::CheckAssetsVersion()
{
    // Only allow CheckAssetsVersion to be called once
    if (assets_version_checked_)
    {
        return;
    }
    assets_version_checked_ = true;

    auto &board = Board::GetInstance();
    auto display = board.GetDisplay();
    auto &assets = Assets::GetInstance();

    if (!assets.partition_valid())
    {
        ESP_LOGW(TAG, "Assets partition is disabled for board %s", BOARD_NAME);
        return;
    }

    Settings settings("assets", true);
    // Check if there is a new assets need to be downloaded
    std::string download_url = settings.GetString("download_url");

    if (!download_url.empty())
    {
        settings.EraseKey("download_url");

        char message[256];
        snprintf(message, sizeof(message), Lang::Strings::FOUND_NEW_ASSETS, download_url.c_str());
        Alert(Lang::Strings::LOADING_ASSETS, message, "cloud_arrow_down", Lang::Sounds::OGG_UPGRADE);

        // Wait for the audio service to be idle for 3 seconds
        vTaskDelay(pdMS_TO_TICKS(3000));
        SetDeviceState(kDeviceStateUpgrading);
        board.SetPowerSaveLevel(PowerSaveLevel::PERFORMANCE);
        display->SetChatMessage("system", Lang::Strings::PLEASE_WAIT);

        bool success = assets.Download(download_url, [this, display](int progress, size_t speed) -> void {
            char buffer[64];
            snprintf(buffer, sizeof(buffer), "%d%% %zu KB/s", progress, speed / 1024);
            display->SetChatMessage("system", buffer);
        });

        if (success)
        {
            // Check for new firmware version after assets download
            if (ota_->HasNewVersion())
            {
                if (UpgradeFirmware(ota_->GetFirmwareUrl(), ota_->GetFirmwareVersion()))
                {
                    return; // This line will never be reached after reboot
                }
                // If upgrade failed, continue to normal operation
            }

            // No new version, mark the current version as valid
            ota_->MarkCurrentVersionValid();

            if (!ota_->HasActivationCode() && !ota_->HasActivationChallenge())
            {
                // Exit early if no activation needed
                return;
            }

            display->SetStatus(Lang::Strings::ACTIVATION);
            // Activation code is shown to the user and waiting for the user to input
            if (ota_->HasActivationCode())
            {
                ShowActivationCode(ota_->GetActivationCode(), ota_->GetActivationMessage());
            }

            // This will block the loop until the activation is done or timeout
            for (int i = 0; i < 10; ++i)
            {
                ESP_LOGI(TAG, "Activating... %d/%d", i + 1, 10);
                esp_err_t err = ota_->Activate();
                if (err == ESP_OK)
                {
                    break;
                }
                else if (err == ESP_ERR_TIMEOUT)
                {
                    vTaskDelay(pdMS_TO_TICKS(3000));
                }
                else
                {
                    vTaskDelay(pdMS_TO_TICKS(10000));
                }
                if (GetDeviceState() == kDeviceStateIdle)
                {
                    break;
                }
            }
        }
        else
        {
            ESP_LOGE(TAG, "Assets download failed");
            Alert(Lang::Strings::ERROR, Lang::Strings::ASSETS_DOWNLOAD_FAILED, "circle_xmark", Lang::Sounds::OGG_EXCLAMATION);
        }
    }
}

void Application::CheckNewVersion()
{
    const int MAX_RETRY = 10;
    int retry_count = 0;
    int retry_delay = 10; // Initial retry delay in seconds

    auto &board = Board::GetInstance();
    while (true)
    {
        auto display = board.GetDisplay();
        display->SetStatus(Lang::Strings::CHECKING_NEW_VERSION);

        esp_err_t err = ota_->CheckVersion();
        if (err != ESP_OK)
        {
            retry_count++;
            if (retry_count >= MAX_RETRY)
            {
                ESP_LOGE(TAG, "Too many retries, exit version check");
                return;
            }

            char error_message[128];
            snprintf(error_message, sizeof(error_message), "code=%d, url=%s", err, ota_->GetCheckVersionUrl().c_str());
            char buffer[256];
            snprintf(buffer, sizeof(buffer), Lang::Strings::CHECK_NEW_VERSION_FAILED, retry_delay, error_message);
            Alert(Lang::Strings::ERROR, buffer, "cloud_slash", Lang::Sounds::OGG_EXCLAMATION);

            ESP_LOGW(TAG, "Check new version failed, retry in %d seconds (%d/%d)", retry_delay, retry_count, MAX_RETRY);
            for (int i = 0; i < retry_delay; i++)
            {
                vTaskDelay(pdMS_TO_TICKS(1000));
                if (GetDeviceState() == kDeviceStateIdle)
                {
                    break;
                }
            }
            retry_delay *= 2; // Double the retry delay
            continue;
        }
        retry_count = 0;
        retry_delay = 10; // Reset retry delay

        if (ota_->HasNewVersion())
        {
            // Found new version, perform upgrade
            std::string firmware_url = ota_->GetFirmwareUrl();
            std::string firmware_version = ota_->GetFirmwareVersion();

            if (!firmware_url.empty())
            {
                ESP_LOGI(TAG, "New firmware version available: %s", firmware_version.c_str());
                if (!UpgradeFirmware(firmware_url, firmware_version))
                {
                    // Upgrade failed, continue with activation
                    ESP_LOGW(TAG, "Firmware upgrade failed, continuing with activation");
                }
                // If upgrade succeeds, UpgradeFirmware will reboot the device
            }
        }
        else
        {
            ESP_LOGI(TAG, "No new firmware version available");
        }

        // Exit the loop after checking version (whether new version exists or not)
        break;
    }
}

void Application::InitializeProtocol()
{
    Settings settings("device");
    std::string protocol_type = settings.GetString("protocol", "mqtt");

    if (protocol_type == "websocket") {
        auto websocket_protocol = std::make_unique<WebsocketProtocol>();
        websocket_protocol->SetMessageCallback([this](const std::string& payload) {
            HandleProtocolMessage(payload);
        });
        websocket_protocol->SetConnectionCallback([this](bool connected) {
            if (connected) {
                xEventGroupSetBits(event_group_, MAIN_EVENT_NETWORK_CONNECTED);
            } else {
                xEventGroupSetBits(event_group_, MAIN_EVENT_NETWORK_DISCONNECTED);
            }
        });
        protocol_ = std::move(websocket_protocol);
    } else {
        // Default to MQTT protocol
        auto mqtt_protocol = std::make_unique<MqttProtocol>();
        mqtt_protocol->SetMessageCallback([this](const std::string& payload) {
            HandleProtocolMessage(payload);
        });
        mqtt_protocol->SetConnectionCallback([this](bool connected) {
            if (connected) {
                xEventGroupSetBits(event_group_, MAIN_EVENT_NETWORK_CONNECTED);
            } else {
                xEventGroupSetBits(event_group_, MAIN_EVENT_NETWORK_DISCONNECTED);
            }
        });
        protocol_ = std::move(mqtt_protocol);
    }

    // Initialize the protocol
    if (protocol_) {
        protocol_->Initialize();
    }
}

void Application::ShowActivationCode(const std::string &code, const std::string &message)
{
    struct digit_sound
    {
        char digit;
        const std::string_view &sound;
    };
    static const std::array<digit_sound, 10> digit_sounds{{digit_sound{'0', Lang::Sounds::OGG_0},
                                                           digit_sound{'1', Lang::Sounds::OGG_1},
                                                           digit_sound{'2', Lang::Sounds::OGG_2},
                                                           digit_sound{'3', Lang::Sounds::OGG_3},
                                                           digit_sound{'4', Lang::Sounds::OGG_4},
                                                           digit_sound{'5', Lang::Sounds::OGG_5},
                                                           digit_sound{'6', Lang::Sounds::OGG_6},
                                                           digit_sound{'7', Lang::Sounds::OGG_7},
                                                           digit_sound{'8', Lang::Sounds::OGG_8},
                                                           digit_sound{'9', Lang::Sounds::OGG_9}}};

    // This sentence uses 9KB of SRAM, so we need to wait for it to finish
    Alert(Lang::Strings::ACTIVATION, message.c_str(), "link", Lang::Sounds::OGG_ACTIVATION);

    // Wait a bit for the initial alert sound to start playing
    vTaskDelay(pdMS_TO_TICKS(1000));

    // Play each digit sound sequentially
    for (const auto &digit : code)
    {
        auto it = std::find_if(digit_sounds.begin(), digit_sounds.end(),
                               [digit](const digit_sound &ds)
                               { return ds.digit == digit; });
        if (it != digit_sounds.end())
        {
            audio_service_.PlaySound(it->sound);
            // Wait for the digit sound to finish playing
            vTaskDelay(pdMS_TO_TICKS(1000));
        }
    }
}

void Application::HandleToggleChatEvent()
{
    auto state = GetDeviceState();

    if (state == kDeviceStateActivating)
    {
        SetDeviceState(kDeviceStateIdle);
        return;
    }
    else if (state == kDeviceStateWifiConfiguring)
    {
        audio_service_.EnableAudioTesting(true);
        SetDeviceState(kDeviceStateAudioTesting);
        return;
    }
    else if (state == kDeviceStateAudioTesting)
    {
        audio_service_.EnableAudioTesting(false);
        SetDeviceState(kDeviceStateWifiConfiguring);
        return;
    }

    if (!protocol_)
    {
        ESP_LOGE(TAG, "Protocol not initialized");
        return;
    }

    if (state == kDeviceStateIdle)
    {
        if (!protocol_->IsAudioChannelOpened())
        {
            SetDeviceState(kDeviceStateConnecting);
            if (!protocol_->OpenAudioChannel())
            {
                return;
            }
        }

        SetListeningMode(aec_mode_ == kAecOff ? kListeningModeAutoStop : kListeningModeRealtime);
    }
    else if (state == kDeviceStateSpeaking)
    {
        AbortSpeaking(kAbortReasonNone);
    }
    else if (state == kDeviceStateListening)
    {
        protocol_->CloseAudioChannel();
    }
}

void Application::HandleStartListeningEvent()
{
    auto state = GetDeviceState();

    if (state == kDeviceStateActivating)
    {
        SetDeviceState(kDeviceStateIdle);
        return;
    }
    else if (state == kDeviceStateWifiConfiguring)
    {
        audio_service_.EnableAudioTesting(true);
        SetDeviceState(kDeviceStateAudioTesting);
        return;
    }

    if (!protocol_)
    {
        ESP_LOGE(TAG, "Protocol not initialized");
        return;
    }

    if (state == kDeviceStateIdle)
    {
        if (!protocol_->IsAudioChannelOpened())
        {
            SetDeviceState(kDeviceStateConnecting);
            if (!protocol_->OpenAudioChannel())
            {
                return;
            }
        }

        SetListeningMode(kListeningModeManualStop);
    }
    else if (state == kDeviceStateSpeaking)
    {
        AbortSpeaking(kAbortReasonNone);
        SetListeningMode(kListeningModeManualStop);
    }
}

void Application::HandleWakeWordDetectedEvent()
{
    if (!protocol_)
    {
        return;
    }

    auto state = GetDeviceState();

    if (state == kDeviceStateIdle)
    {
        audio_service_.EncodeWakeWord();

        if (!protocol_->IsAudioChannelOpened())
        {
            SetDeviceState(kDeviceStateConnecting);
            if (!protocol_->OpenAudioChannel())
            {
                audio_service_.EnableWakeWordDetection(true);
                return;
            }
        }

        auto wake_word = audio_service_.GetLastWakeWord();
        ESP_LOGI(TAG, "Wake word detected: %s", wake_word.c_str());
#if CONFIG_SEND_WAKE_WORD_DATA
        // Encode and send the wake word data to the server
        while (auto packet = audio_service_.PopWakeWordPacket())
        {
            protocol_->SendAudio(std::move(packet));
        }
        // Set the chat state to wake word detected
        protocol_->SendWakeWordDetected(wake_word);
        SetListeningMode(aec_mode_ == kAecOff ? kListeningModeAutoStop : kListeningModeRealtime);
#else
        // Set flag to play popup sound after state changes to listening
        // (PlaySound here would be cleared by ResetDecoder in EnableVoiceProcessing)
        play_popup_on_listening_ = true;
        SetListeningMode(aec_mode_ == kAecOff ? kListeningModeAutoStop : kListeningModeRealtime);
#endif
    }
    else if (state == kDeviceStateSpeaking)
    {
        AbortSpeaking(kAbortReasonWakeWordDetected);
    }
    else if (state == kDeviceStateActivating)
    {
        // Restart the activation check if the wake word is detected during activation
        SetDeviceState(kDeviceStateIdle);
    }
}

void Application::HandleStateChangedEvent()
{
    auto old_state = state_machine_.GetPreviousState();
    auto new_state = state_machine_.GetCurrentState();

    ESP_LOGI(TAG, "State changed from %d to %d", static_cast<int>(old_state), static_cast<int>(new_state));

    auto display = Board::GetInstance().GetDisplay();

    switch (new_state) {
        case kDeviceStateStarting:
            display->SetStatus(Lang::Strings::STARTING);
            display->SetEmotion("neutral");
            break;

        case kDeviceStateWifiConfiguring:
            display->SetStatus(Lang::Strings::WIFI_CONFIG);
            display->SetEmotion("wifi");
            display->SetChatMessage("system", Lang::Strings::PRESS_AND_HOLD_TO_CONFIG_WIFI);
            break;

        case kDeviceStateAudioTesting:
            display->SetStatus(Lang::Strings::AUDIO_TESTING);
            display->SetEmotion("volume_high");
            break;

        case kDeviceStateActivating:
            display->SetStatus(Lang::Strings::ACTIVATION);
            display->SetEmotion("cloud");
            break;

        case kDeviceStateUpgrading:
            display->SetStatus(Lang::Strings::OTA_UPGRADE);
            display->SetEmotion("download");
            break;

        case kDeviceStateIdle:
            if (old_state == kDeviceStateSpeaking || old_state == kDeviceStateListening) {
                display->SetChatMessage("system", "");
            }
            display->SetStatus(Lang::Strings::STANDBY);
            display->SetEmotion("neutral");
            audio_service_.EnableWakeWordDetection(true);
            break;

        case kDeviceStateConnecting:
            display->SetStatus(Lang::Strings::CONNECTING);
            display->SetEmotion("cloud");
            break;

        case kDeviceStateListening:
            display->SetStatus(Lang::Strings::LISTENING);
            display->SetEmotion("microphone_lines");
            if (play_popup_on_listening_) {
                audio_service_.PlaySound(Lang::Sounds::OGG_POPUP);
                play_popup_on_listening_ = false;
            }
            audio_service_.EnableVoiceProcessing(true);
            audio_service_.EnableWakeWordDetection(false);
            break;

        case kDeviceStateSpeaking:
            display->SetStatus(Lang::Strings::SPEAKING);
            display->SetEmotion("message");
            audio_service_.EnableVoiceProcessing(false);
            audio_service_.EnableWakeWordDetection(false);
            break;

        default:
            break;
    }

    // Update LED state
    auto led = Board::GetInstance().GetLed();
    if (led) {
        led->OnStateChanged();
    }
}

bool Application::UpgradeFirmware(const std::string &url, const std::string &version)
{
    auto &board = Board::GetInstance();
    auto display = board.GetDisplay();

    std::string upgrade_url = url;
    std::string version_info = version.empty() ? "(Manual upgrade)" : version;

    // Close audio channel if it's open
    if (protocol_ && protocol_->IsAudioChannelOpened())
    {
        ESP_LOGI(TAG, "Closing audio channel before firmware upgrade");
        protocol_->CloseAudioChannel();
    }
    ESP_LOGI(TAG, "Starting firmware upgrade from URL: %s", upgrade_url.c_str());

    Alert(Lang::Strings::OTA_UPGRADE, Lang::Strings::UPGRADING, "download", Lang::Sounds::OGG_UPGRADE);
    vTaskDelay(pdMS_TO_TICKS(3000));

    SetDeviceState(kDeviceStateUpgrading);

    std::string message = std::string(Lang::Strings::NEW_VERSION) + version_info;
    display->SetChatMessage("system", message.c_str());

    board.SetPowerSaveLevel(PowerSaveLevel::PERFORMANCE);
    audio_service_.Stop();
    vTaskDelay(pdMS_TO_TICKS(1000));

    bool upgrade_success = Ota::Upgrade(upgrade_url, [display](int progress, size_t speed)
                                        { std::thread([display, progress, speed]()
                                                      {
            char buffer[32];
            snprintf(buffer, sizeof(buffer), "%d%% %uKB/s", progress, speed / 1024);
            display->SetChatMessage("system", buffer); })
                                              .detach(); });

    if (!upgrade_success)
    {
        // Upgrade failed, restart audio service and continue running
        ESP_LOGE(TAG, "Firmware upgrade failed, restarting audio service and continuing operation...");
        audio_service_.Start();                             // Restart audio service
        board.SetPowerSaveLevel(PowerSaveLevel::LOW_POWER); // Restore power save level
        Alert(Lang::Strings::ERROR, Lang::Strings::UPGRADE_FAILED, "circle_xmark", Lang::Sounds::OGG_EXCLAMATION);
        vTaskDelay(pdMS_TO_TICKS(3000));
        return false;
    }
    else
    {
        // Upgrade success, reboot immediately
        ESP_LOGI(TAG, "Firmware upgrade successful, rebooting...");
        display->SetChatMessage("system", "Upgrade successful, rebooting...");
        vTaskDelay(pdMS_TO_TICKS(1000)); // Brief pause to show message
        Reboot();
        return true;
    }
}

void Application::WakeWordInvoke(const std::string &wake_word)
{
    if (!protocol_)
    {
        return;
    }

    auto state = GetDeviceState();

    if (state == kDeviceStateIdle)
    {
        audio_service_.EncodeWakeWord();

        if (!protocol_->IsAudioChannelOpened())
        {
            SetDeviceState(kDeviceStateConnecting);
            if (!protocol_->OpenAudioChannel())
            {
                audio_service_.EnableWakeWordDetection(true);
                return;
            }
        }

        ESP_LOGI(TAG, "Wake word detected: %s", wake_word.c_str());
#if CONFIG_SEND_WAKE_WORD_DATA
        // Encode and send the wake word data to the server
        while (auto packet = audio_service_.PopWakeWordPacket())
        {
            protocol_->SendAudio(std::move(packet));
        }
        // Set the chat state to wake word detected
        protocol_->SendWakeWordDetected(wake_word);
        SetListeningMode(aec_mode_ == kAecOff ? kListeningModeAutoStop : kListeningModeRealtime);
#else
        // Set flag to play popup sound after state changes to listening
        // (PlaySound here would be cleared by ResetDecoder in EnableVoiceProcessing)
        play_popup_on_listening_ = true;
        SetListeningMode(aec_mode_ == kAecOff ? kListeningModeAutoStop : kListeningModeRealtime);
#endif
    }
    else if (state == kDeviceStateSpeaking)
    {
        Schedule([this]()
                 { AbortSpeaking(kAbortReasonNone); });
    }
    else if (state == kDeviceStateListening)
    {
        Schedule([this]()
                 {
            if (protocol_) {
                protocol_->CloseAudioChannel();
            } });
    }
    else if (state == kDeviceStateActivating)
    {
        // Restart the activation check if the wake word is detected during activation
        SetDeviceState(kDeviceStateIdle);
    }
}

void Application::SetAecMode(AecMode mode)
{
    aec_mode_ = mode;
    Schedule([this]()
             {
        auto& board = Board::GetInstance();
        auto display = board.GetDisplay();
        switch (aec_mode_) {
        case kAecOff:
            audio_service_.EnableDeviceAec(false);
            display->ShowNotification(Lang::Strings::RTC_MODE_OFF);
            break;
        case kAecOnServerSide:
            audio_service_.EnableDeviceAec(false);
            display->ShowNotification(Lang::Strings::RTC_MODE_ON);
            break;
        case kAecOnDeviceSide:
            audio_service_.EnableDeviceAec(true);
            display->ShowNotification(Lang::Strings::RTC_MODE_ON);
            break;
        }

        // If the AEC mode is changed, close the audio channel
        if (protocol_ && protocol_->IsAudioChannelOpened()) {
            protocol_->CloseAudioChannel();
        } });
}

bool Assets::InitializePartition()
{
    // Find the assets partition
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        return false;
    }

    ESP_LOGI(TAG, "Found assets partition, size: %u bytes", partition_->size);

    // Map the entire partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, SPI_FLASH_MMAP_DATA, &mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "Mapped assets partition to address %p", mmap_root_);

    // Clear existing assets map
    assets_.clear();

    // Parse the mapped data to build asset index
    const char* data = static_cast<const char*>(mmap_root_);

    // Check magic header (assuming first 4 bytes are magic number)
    if (data[0] != 'A' || data[1] != 'S' || data[2] != 'E' || data[3] != 'T') {
        ESP_LOGE(TAG, "Invalid assets partition magic number");
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return false;
    }

    // Read header information (assuming offset 4-7 contains table offset, 8-11 contains table size)
    uint32_t table_offset = *reinterpret_cast<const uint32_t*>(data + 4);
    uint32_t table_size = *reinterpret_cast<const uint32_t*>(data + 8);

    // Validate table bounds
    if (table_offset + table_size > partition_->size) {
        ESP_LOGE(TAG, "Assets table extends beyond partition bounds");
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return false;
    }

    // Calculate and verify checksum
    uint32_t stored_checksum = *reinterpret_cast<const uint32_t*>(data + 12);
    uint32_t calculated_checksum = CalculateChecksum(data + 16, table_offset + table_size - 16);

    if (stored_checksum != calculated_checksum) {
        ESP_LOGE(TAG, "Assets partition checksum mismatch: stored=0x%04X, calculated=0x%04X", 
                 stored_checksum, calculated_checksum);
        checksum_valid_ = false;
    } else {
        ESP_LOGI(TAG, "Assets partition checksum verified: 0x%04X", stored_checksum);
        checksum_valid_ = true;
    }

    // Parse asset table entries
    const mmap_assets_table* table = reinterpret_cast<const mmap_assets_table*>(data + table_offset);
    uint32_t entry_count = table_size / sizeof(mmap_assets_table);

    for (uint32_t i = 0; i < entry_count; i++) {
        const mmap_assets_table& entry = table[i];

        // Skip empty entries
        if (entry.asset_name[0] == '\0' || entry.asset_size == 0) {
            continue;
        }

        // Validate asset bounds
        if (entry.asset_offset + entry.asset_size > partition_->size) {
            ESP_LOGW(TAG, "Asset '%s' extends beyond partition bounds, skipping", entry.asset_name);
            continue;
        }

        // Add to assets map
        AssetInfo info;
        info.size = entry.asset_size;
        info.offset = entry.asset_offset;
        info.width = entry.asset_width;
        info.height = entry.asset_height;

        assets_[std::string(entry.asset_name)] = info;

        ESP_LOGD(TAG, "Found asset: %s, size: %u, offset: %u", 
                 entry.asset_name, entry.asset_size, entry.asset_offset);
    }

    ESP_LOGI(TAG, "Initialized assets partition with %d assets", assets_.size());
    return true;
}

bool Assets::Apply()
{
    ESP_LOGI(TAG, "Applying assets from index.json");

    // First check if we have valid assets partition
    if (!partition_valid_ || !checksum_valid_)
    {
        ESP_LOGE(TAG, "Assets partition is not valid or checksum failed");
        return false;
    }

    // Get the index.json asset data
    void* index_data_ptr = nullptr;
    size_t index_data_size = 0;

    if (!GetAssetData("index.json", index_data_ptr, index_data_size))
    {
        ESP_LOGE(TAG, "Failed to get index.json asset data");
        return false;
    }

    // Parse the JSON configuration
    std::string json_content(static_cast<const char*>(index_data_ptr), index_data_size);

    cJSON* root = cJSON_Parse(json_content.c_str());
    if (root == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return false;
    }

    bool success = true;

    // Check asset version
    cJSON* version_item = cJSON_GetObjectItem(root, "version");
    if (version_item && cJSON_IsString(version_item))
    {
        ESP_LOGI(TAG, "Asset package version: %s", version_item->valuestring);
    }
    else
    {
        ESP_LOGW(TAG, "No version found in index.json");
    }

    // Apply UI theme assets
    cJSON* ui_theme = cJSON_GetObjectItem(root, "ui_theme");
    if (ui_theme && cJSON_IsObject(ui_theme))
    {
        cJSON* theme_name = cJSON_GetObjectItem(ui_theme, "name");
        if (theme_name && cJSON_IsString(theme_name))
        {
            ESP_LOGI(TAG, "Applying UI theme: %s", theme_name->valuestring);

            // Apply fonts
            cJSON* fonts = cJSON_GetObjectItem(ui_theme, "fonts");
            if (fonts && cJSON_IsArray(fonts))
            {
                int font_count = cJSON_GetArraySize(fonts);
                for (int i = 0; i < font_count; i++)
                {
                    cJSON* font_item = cJSON_GetArrayItem(fonts, i);
                    if (font_item && cJSON_IsObject(font_item))
                    {
                        cJSON* font_name = cJSON_GetObjectItem(font_item, "name");
                        cJSON* font_file = cJSON_GetObjectItem(font_item, "file");

                        if (font_name && cJSON_IsString(font_name) && 
                            font_file && cJSON_IsString(font_file))
                        {
                            void* font_data_ptr = nullptr;
                            size_t font_data_size = 0;

                            if (GetAssetData(font_file->valuestring, font_data_ptr, font_data_size))
                            {
                                // Register font with LVGL or custom font system
                                ESP_LOGI(TAG, "Loading font: %s from %s", 
                                         font_name->valuestring, font_file->valuestring);

                                // Here you would typically register the font with your display system
                                // For example, with LVGL you might create a font descriptor
                            }
                            else
                            {
                                ESP_LOGE(TAG, "Failed to load font file: %s", font_file->valuestring);
                                success = false;
                            }
                        }
                    }
                }
            }

            // Apply emojis if specified
            cJSON* emojis = cJSON_GetObjectItem(ui_theme, "emojis");
            if (emojis && cJSON_IsString(emojis))
            {
                void* emoji_data_ptr = nullptr;
                size_t emoji_data_size = 0;

                if (GetAssetData(emojis->valuestring, emoji_data_ptr, emoji_data_size))
                {
                    ESP_LOGI(TAG, "Loading emojis from: %s", emojis->valuestring);
                    // Initialize emoji display system
                    EmoteDisplay::GetInstance().LoadEmojis(emoji_data_ptr, emoji_data_size);
                }
                else
                {
                    ESP_LOGE(TAG, "Failed to load emoji file: %s", emojis->valuestring);
                    success = false;
                }
            }
        }
    }

    // Apply speech recognition models
    cJSON* speech_models = cJSON_GetObjectItem(root, "speech_models");
    if (speech_models && cJSON_IsArray(speech_models))
    {
        int model_count = cJSON_GetArraySize(speech_models);
        for (int i = 0; i < model_count; i++)
        {
            cJSON* model_item = cJSON_GetArrayItem(speech_models, i);
            if (model_item && cJSON_IsObject(model_item))
            {
                cJSON* model_name = cJSON_GetObjectItem(model_item, "name");
                cJSON* model_file = cJSON_GetObjectItem(model_item, "file");
                cJSON* model_type = cJSON_GetObjectItem(model_item, "type");

                if (model_name && cJSON_IsString(model_name) &&
                    model_file && cJSON_IsString(model_file))
                {
                    void* model_data_ptr = nullptr;
                    size_t model_data_size = 0;

                    if (GetAssetData(model_file->valuestring, model_data_ptr, model_data_size))
                    {
                        ESP_LOGI(TAG, "Loading speech model: %s (%s) from %s", 
                                 model_name->valuestring,
                                 model_type ? model_type->valuestring : "unknown",
                                 model_file->valuestring);

                        // Here you would initialize your speech recognition system
                        // with the loaded model data
                        // Example: SpeechRecognition::LoadModel(model_name->valuestring, 
                        //                                      model_data_ptr, model_data_size);
                    }
                    else
                    {
                        ESP_LOGE(TAG, "Failed to load speech model file: %s", model_file->valuestring);
                        success = false;
                    }
                }
            }
        }
    }

    // Apply any additional assets
    cJSON* additional_assets = cJSON_GetObjectItem(root, "additional_assets");
    if (additional_assets && cJSON_IsArray(additional_assets))
    {
        int asset_count = cJSON_GetArraySize(additional_assets);
        for (int i = 0; i < asset_count; i++)
        {
            cJSON* asset_item = cJSON_GetArrayItem(additional_assets, i);
            if (asset_item && cJSON_IsObject(asset_item))
            {
                cJSON* asset_name = cJSON_GetObjectItem(asset_item, "name");
                cJSON* asset_file = cJSON_GetObjectItem(asset_item, "file");
                cJSON* asset_type = cJSON_GetObjectItem(asset_item, "type");

                if (asset_name && cJSON_IsString(asset_name) &&
                    asset_file && cJSON_IsString(asset_file))
                {
                    void* asset_data_ptr = nullptr;
                    size_t asset_data_size = 0;

                    if (GetAssetData(asset_file->valuestring, asset_data_ptr, asset_data_size))
                    {
                        ESP_LOGI(TAG, "Loading additional asset: %s (%s) from %s", 
                                 asset_name->valuestring,
                                 asset_type ? asset_type->valuestring : "unknown",
                                 asset_file->valuestring);

                        // Process additional assets as needed by your application
                    }
                    else
                    {
                        ESP_LOGE(TAG, "Failed to load additional asset file: %s", asset_file->valuestring);
                        success = false;
                    }
                }
            }
        }
    }

    cJSON_Delete(root);

    if (success)
    {
        ESP_LOGI(TAG, "All assets applied successfully");
    }
    else
    {
        ESP_LOGE(TAG, "Some assets failed to apply");
    }

    return success;
}

bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    ESP_LOGI(TAG, "Starting download from %s", url.c_str());

    // Find the assets partition
    const esp_partition_t* partition = esp_partition_find_first(ESP_PARTITION_TYPE_ANY, ESP_PARTITION_SUBTYPE_ANY, "assets");
    if (partition == nullptr) {
        ESP_LOGE(TAG, "No assets partition found");
        return false;
    }

    // Initialize HTTP client
    esp_http_client_config_t config = {};
    config.url = url.c_str();
    config.timeout_ms = 30000; // 30 second timeout

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    // Open HTTP connection
    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    // Get content length
    int content_length = esp_http_client_fetch_headers(client);
    if (content_length < 0) {
        ESP_LOGE(TAG, "Failed to fetch headers");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Content length: %d bytes", content_length);
    ESP_LOGI(TAG, "Partition size: %d bytes", partition->size);

    // Check if content fits in partition
    if (content_length > (int)partition->size) {
        ESP_LOGE(TAG, "Content size (%d) exceeds partition size (%d)", content_length, partition->size);
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Erase the partition before writing
    ESP_LOGI(TAG, "Erasing partition...");
    err = esp_partition_erase_range(partition, 0, partition->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase partition: %s", esp_err_to_name(err));
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Download and write data
    const size_t buffer_size = 4096;
    uint8_t* buffer = (uint8_t*)malloc(buffer_size);
    if (buffer == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate download buffer");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    size_t total_written = 0;
    size_t offset = 0;
    auto start_time = esp_timer_get_time();
    auto last_progress_time = start_time;
    int last_progress = 0;

    while (total_written < content_length) {
        int read_len = esp_http_client_read(client, (char*)buffer, buffer_size);
        if (read_len < 0) {
            ESP_LOGE(TAG, "HTTP read failed");
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        if (read_len == 0) {
            // No more data
            break;
        }

        // Write to flash
        err = esp_partition_write(partition, offset, buffer, read_len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to partition: %s", esp_err_to_name(err));
            free(buffer);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        total_written += read_len;
        offset += read_len;

        // Calculate progress and speed
        auto current_time = esp_timer_get_time();
        int progress = (total_written * 100) / content_length;

        // Update progress callback periodically (every 100ms or when progress changes significantly)
        if (progress_callback && 
            (progress != last_progress || (current_time - last_progress_time) > 100000)) {

            size_t elapsed_ms = (current_time - start_time) / 1000;
            size_t speed = elapsed_ms > 0 ? (total_written * 1000) / elapsed_ms : 0;

            progress_callback(progress, speed);
            last_progress = progress;
            last_progress_time = current_time;
        }
    }

    free(buffer);
    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    if (total_written != content_length) {
        ESP_LOGE(TAG, "Incomplete download: expected %d bytes, got %d bytes", content_length, total_written);
        return false;
    }

    ESP_LOGI(TAG, "Download completed successfully: %d bytes written", total_written);

    // Verify the written data by re-initializing
    return InitializePartition();
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    // Allow self-transitions by default
    if (from == to)
        return true;

    switch (from)
    {
    case kDeviceStateUnknown:
        return to == kDeviceStateStarting;

    case kDeviceStateStarting:
        return to == kDeviceStateWifiConfiguring || to == kDeviceStateFatalError;

    case kDeviceStateWifiConfiguring:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateIdle:
        return to == kDeviceStateConnecting ||
               to == kDeviceStateListening ||
               to == kDeviceStateSpeaking ||
               to == kDeviceStateUpgrading ||
               to == kDeviceStateActivating ||
               to == kDeviceStateAudioTesting ||
               to == kDeviceStateFatalError;

    case kDeviceStateConnecting:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateListening:
        return to == kDeviceStateIdle || to == kDeviceStateSpeaking || to == kDeviceStateFatalError;

    case kDeviceStateSpeaking:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateUpgrading:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateActivating:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateAudioTesting:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateFatalError:
        // Fatal error is terminal - no outgoing transitions allowed
        return false;

    default:
        // Invalid 'from' state
        return false;
    }
}

bool DeviceStateMachine::IsValidTransition(DeviceState from, DeviceState to) const
{
    switch (from)
    {
    case kDeviceStateUnknown:
        return to == kDeviceStateStarting;

    case kDeviceStateStarting:
        return to == kDeviceStateWifiConfiguring || to == kDeviceStateFatalError;

    case kDeviceStateWifiConfiguring:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateIdle:
        return to == kDeviceStateConnecting ||
               to == kDeviceStateUpgrading ||
               to == kDeviceStateActivating ||
               to == kDeviceStateAudioTesting ||
               to == kDeviceStateFatalError;

    case kDeviceStateConnecting:
        return to == kDeviceStateListening ||
               to == kDeviceStateSpeaking ||
               to == kDeviceStateFatalError;

    case kDeviceStateListening:
        return to == kDeviceStateSpeaking ||
               to == kDeviceStateIdle ||
               to == kDeviceStateFatalError;

    case kDeviceStateSpeaking:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateUpgrading:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateActivating:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateAudioTesting:
        return to == kDeviceStateIdle || to == kDeviceStateFatalError;

    case kDeviceStateFatalError:
        // Fatal error is terminal unless reset logic handles re-entry
        return false;

    default:
        return false;
    }

    // Any state can transition to fatal_error as a catch-all failure handling
    if (to == kDeviceStateFatalError)
        return true;

    return false;
}

void McpServer::AddCommonTools()
{
    // Get device status
    AddTool("get_device_status", "Get the current device status including battery level, charging state, etc.",
            PropertyList(),
            [](const PropertyList &properties) -> ReturnValue
            {
                auto &board = Board::GetInstance();
                return board.GetDeviceStatusJson();
            });

    // Set audio volume
    AddTool("set_audio_volume", "Set the audio volume level",
            PropertyList({Property("volume", kPropertyTypeInteger, "Volume level (0-100)", 50, 0, 100)}),
            [](const PropertyList &properties) -> ReturnValue
            {
                auto volume = properties["volume"].value<int>();
                auto &board = Board::GetInstance();
                auto audio = board.GetAudioOutput();
                if (audio)
                {
                    audio->SetVolume(volume);
                    Settings settings("audio", true);
                    settings.SetInteger("volume", volume);
                }
                return true;
            });

    // Adjust screen brightness
    AddTool("set_screen_brightness", "Adjust the screen brightness",
            PropertyList({Property("brightness", kPropertyTypeInteger, "Brightness level (0-100)", 50, 0, 100)}),
            [](const PropertyList &properties) -> ReturnValue
            {
                auto brightness = properties["brightness"].value<int>();
                auto &board = Board::GetInstance();
                auto display = board.GetDisplay();
                if (display)
                {
                    display->SetBacklight(brightness);
                    Settings settings("display", true);
                    settings.SetInteger("brightness", brightness);
                }
                return true;
            });

    // Change display theme
    AddTool("set_display_theme", "Change the display theme",
            PropertyList({Property("theme", kPropertyTypeString, "Theme name (light/dark)", "dark")}),
            [](const PropertyList &properties) -> ReturnValue
            {
                auto theme = properties["theme"].value<std::string>();
                auto &board = Board::GetInstance();
                auto display = board.GetDisplay();
                if (display)
                {
                    if (theme == "light")
                    {
                        display->SetTheme(LvglTheme::kLight);
                    }
                    else
                    {
                        display->SetTheme(LvglTheme::kDark);
                    }
                    Settings settings("display", true);
                    settings.SetString("theme", theme);
                }
                return true;
            });
}

