    // Display control
#ifdef HAVE_LVGL
    auto display = dynamic_cast<LvglDisplay *>(Board::GetInstance().GetDisplay());
    if (display)
    {
        AddUserOnlyTool("self.screen.get_info", "Information about the screen, including width, height, etc.",
                        PropertyList(),
                        [display](const PropertyList &properties) -> ReturnValue
                        {
                            cJSON *json = cJSON_CreateObject();
                            cJSON_AddNumberToObject(json, "width", display->width());
                            cJSON_AddNumberToObject(json, "height", display->height());
                            if (dynamic_cast<OledDisplay *>(display))
                            {
                                cJSON_AddBoolToObject(json, "monochrome", true);
                            }
                            else
                            {
                                cJSON_AddBoolToObject(json, "monochrome", false);
                            }
                            return json;
                        });

#if CONFIG_LV_USE_SNAPSHOT
        AddUserOnlyTool("self.screen.snapshot", "Snapshot the screen and upload it to a specific URL",
                        PropertyList({Property("url", kPropertyTypeString),
                                      Property("quality", kPropertyTypeInteger, 80, 1, 100)}),
                        [display](const PropertyList &properties) -> ReturnValue
                        {
                            auto url = properties["url"].value<std::string>();
                            auto quality = properties["quality"].value<int>();

                            std::string jpeg_data;
                            if (!display->SnapshotToJpeg(jpeg_data, quality))
                            {
                                throw std::runtime_error("Failed to snapshot screen");
                            }

                            ESP_LOGI(TAG, "Upload snapshot %u bytes to %s", jpeg_data.size(), url.c_str());

                            // Construct multipart/form-data request body
                            std::string boundary = "----ESP32_SCREEN_SNAPSHOT_BOUNDARY";
                            std::string body = "--" + boundary + "\r\n";
                            body += "Content-Disposition: form-data; name=\"file\"; filename=\"snapshot.jpg\"\r\n";
                            body += "Content-Type: image/jpeg\r\n\r\n";
                            body += jpeg_data;
                            body += "\r\n--" + boundary + "--\r\n";

                            // Upload via HTTP POST
                            auto http = Board::GetInstance().GetNetwork()->CreateHttp(3);
                            http->SetUrl(url);
                            http->SetMethod("POST");
                            http->AddHeader("Content-Type", "multipart/form-data; boundary=" + boundary);

                            std::string response;
                            int status_code = http->Post(body, &response);

                            if (status_code < 200 || status_code >= 300) {
                                throw std::runtime_error("HTTP upload failed with status " + std::to_string(status_code));
                            }

                            cJSON *result = cJSON_CreateObject();
                            cJSON_AddStringToObject(result, "status", "uploaded");
                            cJSON_AddNumberToObject(result, "size", jpeg_data.size());
                            cJSON_AddStringToObject(result, "url", url.c_str());
                            return result;
                        });
#endif // CONFIG_LV_USE_SNAPSHOT
    }
#endif // HAVE_LVGL
}

void McpServer::ParseMessage(const cJSON *json)
{
    // Validate JSON-RPC version
    auto jsonrpc = cJSON_GetObjectItem(json, "jsonrpc");
    if (!cJSON_IsString(jsonrpc) || strcmp(jsonrpc->valuestring, "2.0") != 0)
    {
        ESP_LOGE(TAG, "Invalid JSON-RPC version");
        return;
    }

    // Get method
    auto method_obj = cJSON_GetObjectItem(json, "method");
    if (!cJSON_IsString(method_obj))
    {
        ESP_LOGE(TAG, "Missing or invalid method");
        return;
    }
    std::string method = method_obj->valuestring;

    // Get ID (required for all requests we handle)
    auto id_obj = cJSON_GetObjectItem(json, "id");
    if (!id_obj)
    {
        ESP_LOGE(TAG, "Missing ID in request");
        return;
    }
    int id = id_obj->valueint;

    // Get params (optional)
    auto params = cJSON_GetObjectItem(json, "params");

    if (method == "initialize")
    {
        // Handle initialize method
        cJSON *capabilities = cJSON_GetObjectItem(params, "capabilities");
        if (cJSON_IsObject(capabilities))
        {
            ParseCapabilities(capabilities);
        }

        // Return server information
        cJSON *result = cJSON_CreateObject();
        cJSON_AddStringToObject(result, "protocolVersion", "2024-11-05");

        cJSON *server_info = cJSON_CreateObject();
        cJSON_AddStringToObject(server_info, "name", "xiaozhi-esp32");

        const esp_app_desc_t *app_desc = esp_app_get_description();
        if (app_desc)
        {
            cJSON_AddStringToObject(server_info, "version", app_desc->version);
        }
        else
        {
            cJSON_AddStringToObject(server_info, "version", "unknown");
        }
        cJSON_AddItemToObject(result, "serverInfo", server_info);

        char *json_str = cJSON_PrintUnformatted(result);
        ReplyResult(id, std::string(json_str));
        cJSON_free(json_str);
        cJSON_Delete(result);
    }
    else if (method == "tools/list")
    {
        // Handle tools/list method
        std::string cursor = "";
        bool list_user_only_tools = false;

        if (cJSON_IsObject(params))
        {
            auto cursor_obj = cJSON_GetObjectItem(params, "cursor");
            if (cJSON_IsString(cursor_obj))
            {
                cursor = std::string(cursor_obj->valuestring);
            }

            auto user_only_obj = cJSON_GetObjectItem(params, "userOnly");
            if (cJSON_IsBool(user_only_obj))
            {
                list_user_only_tools = cJSON_IsTrue(user_only_obj);
            }
        }

        GetToolsList(id, cursor, list_user_only_tools);
    }
    else if (method == "tools/call")
    {
        // Handle tools/call method
        if (!cJSON_IsObject(params))
        {
            ReplyError(id, "Missing parameters for tools/call");
            return;
        }

        auto name_obj = cJSON_GetObjectItem(params, "name");
        if (!cJSON_IsString(name_obj))
        {
            ReplyError(id, "Missing or invalid tool name");
            return;
        }
        std::string tool_name = name_obj->valuestring;

        auto args_obj = cJSON_GetObjectItem(params, "arguments");
        // args_obj can be null or non-object, which is valid

        DoToolCall(id, tool_name, args_obj);
    }
    else
    {
        ESP_LOGE(TAG, "Unknown method: %s", method.c_str());
        ReplyError(id, "Unknown method: " + method);
    }
}

void McpServer::GetToolsList(int id, const std::string &cursor, bool list_user_only_tools)
{
    constexpr size_t MAX_PAYLOAD_SIZE = 1024; // Limit payload size to prevent oversized responses

    cJSON *result = cJSON_CreateObject();
    cJSON *tools_array = cJSON_CreateArray();
    cJSON_AddItemToObject(result, "tools", tools_array);

    // Handle pagination - start from cursor position or beginning
    size_t start_index = 0;
    if (!cursor.empty()) {
        try {
            start_index = std::stoull(cursor);
        } catch (...) {
            ESP_LOGW(TAG, "Invalid cursor value: %s", cursor.c_str());
        }
    }

    size_t current_size = cJSON_GetArraySize(tools_array);
    std::string next_cursor = "";

    // Iterate through tools starting from cursor position
    for (size_t i = start_index; i < tools_.size(); ++i) {
        const McpTool *tool = tools_[i];

        // Skip user-only tools if not requested
        if (tool->user_only() && !list_user_only_tools) {
            continue;
        }

        // Create tool object
        cJSON *tool_obj = cJSON_CreateObject();
        cJSON_AddStringToObject(tool_obj, "name", tool->name().c_str());
        cJSON_AddStringToObject(tool_obj, "description", tool->description().c_str());

        // Add input schema if properties exist
        if (!tool->properties().empty()) {
            cJSON *input_schema = cJSON_CreateObject();
            cJSON *properties = cJSON_CreateObject();
            cJSON *required = cJSON_CreateArray();

            for (const auto &prop : tool->properties()) {
                cJSON *prop_schema = cJSON_CreateObject();

                switch (prop.type()) {
                    case kPropertyTypeString:
                        cJSON_AddStringToObject(prop_schema, "type", "string");
                        break;
                    case kPropertyTypeInteger:
                        cJSON_AddStringToObject(prop_schema, "type", "integer");
                        if (prop.has_min_value()) {
                            cJSON_AddNumberToObject(prop_schema, "minimum", prop.min_value());
                        }
                        if (prop.has_max_value()) {
                            cJSON_AddNumberToObject(prop_schema, "maximum", prop.max_value());
                        }
                        break;
                    case kPropertyTypeBoolean:
                        cJSON_AddStringToObject(prop_schema, "type", "boolean");
                        break;
                    default:
                        cJSON_AddStringToObject(prop_schema, "type", "string");
                        break;
                }

                if (!prop.description().empty()) {
                    cJSON_AddStringToObject(prop_schema, "description", prop.description().c_str());
                }

                cJSON_AddItemToObject(properties, prop.name().c_str(), prop_schema);

                // Add to required array if no default value
                if (!prop.has_default_value()) {
                    cJSON_AddItemToArray(required, cJSON_CreateString(prop.name().c_str()));
                }
            }

            cJSON_AddItemToObject(input_schema, "properties", properties);
            if (cJSON_GetArraySize(required) > 0) {
                cJSON_AddItemToObject(input_schema, "required", required);
            } else {
                cJSON_Delete(required);
            }

            cJSON_AddItemToObject(tool_obj, "inputSchema", input_schema);
        }

        // Check if adding this tool would exceed payload size limit
        cJSON_AddItemToArray(tools_array, tool_obj);
        char *temp_json = cJSON_PrintUnformatted(result);
        if (temp_json) {
            size_t temp_size = strlen(temp_json);
            cJSON_free(temp_json);

            if (temp_size > MAX_PAYLOAD_SIZE) {
                // Remove the last added tool and set cursor for next page
                cJSON_DeleteItemFromArray(tools_array, cJSON_GetArraySize(tools_array) - 1);
                next_cursor = std::to_string(i);
                break;
            }
        }

        current_size = cJSON_GetArraySize(tools_array);
    }

    // Add next cursor if there are more tools
    if (!next_cursor.empty()) {
        cJSON_AddStringToObject(result, "nextCursor", next_cursor.c_str());
    }

    // Convert to string and send response
    char *json_str = cJSON_PrintUnformatted(result);
    if (json_str) {
        ReplyResult(id, std::string(json_str));
        cJSON_free(json_str);
    } else {
        cJSON_Delete(result);
        ReplyError(id, "Failed to serialize tools list");
        return;
    }

    cJSON_Delete(result);
}

void McpServer::DoToolCall(int id, const std::string &tool_name, const cJSON *arguments_json)
{
    try {
        // Find the tool by name
        auto tool_iter = std::find_if(tools_.begin(), tools_.end(), [&tool_name](const McpTool *tool) {
            return tool->name() == tool_name;
        });

        if (tool_iter == tools_.end()) {
            ESP_LOGE(TAG, "tools/call: Tool not found: %s", tool_name.c_str());
            ReplyError(id, "Tool not found: " + tool_name);
            return;
        }

        // Parse arguments
        PropertyList arguments;
        if (arguments_json != nullptr) {
            auto tool_properties = (*tool_iter)->properties();
            for (const auto& prop : tool_properties) {
                auto arg_item = cJSON_GetObjectItem(arguments_json, prop.name().c_str());
                if (arg_item == nullptr) {
                    // Check if property is required (has no default value)
                    if (!prop.has_default_value()) {
                        ESP_LOGE(TAG, "tools/call: Missing required argument: %s", prop.name().c_str());
                        ReplyError(id, "Missing required argument: " + prop.name());
                        return;
                    }
                    // Use default value
                    arguments.Add(prop);
                } else {
                    // Type checking and conversion
                    Property parsed_prop = prop;
                    switch (prop.type()) {
                        case kPropertyTypeInteger:
                            if (!cJSON_IsNumber(arg_item)) {
                                ESP_LOGE(TAG, "tools/call: Argument %s is not an integer", prop.name().c_str());
                                ReplyError(id, "Argument " + prop.name() + " is not an integer");
                                return;
                            }
                            parsed_prop.set_value(static_cast<int>(arg_item->valuedouble));
                            break;
                        case kPropertyTypeString:
                            if (!cJSON_IsString(arg_item)) {
                                ESP_LOGE(TAG, "tools/call: Argument %s is not a string", prop.name().c_str());
                                ReplyError(id, "Argument " + prop.name() + " is not a string");
                                return;
                            }
                            parsed_prop.set_value(std::string(arg_item->valuestring));
                            break;
                        case kPropertyTypeBoolean:
                            if (!cJSON_IsBool(arg_item)) {
                                ESP_LOGE(TAG, "tools/call: Argument %s is not a boolean", prop.name().c_str());
                                ReplyError(id, "Argument " + prop.name() + " is not a boolean");
                                return;
                            }
                            parsed_prop.set_value(arg_item->valueint != 0);
                            break;
                        default:
                            ESP_LOGE(TAG, "tools/call: Unsupported property type for argument: %s", prop.name().c_str());
                            ReplyError(id, "Unsupported property type for argument: " + prop.name());
                            return;
                    }
                    arguments.Add(parsed_prop);
                }
            }
        } else {
            // No arguments provided, check if all properties have defaults
            auto tool_properties = (*tool_iter)->properties();
            for (const auto& prop : tool_properties) {
                if (!prop.has_default_value()) {
                    ESP_LOGE(TAG, "tools/call: Missing required argument: %s", prop.name().c_str());
                    ReplyError(id, "Missing required argument: " + prop.name());
                    return;
                }
                arguments.Add(prop);
            }
        }

        // Use main thread to call the tool
        auto &app = Application::GetInstance();
        app.Schedule([this, id, tool_iter, arguments = std::move(arguments)]() {
            try {
                ReturnValue result = (*tool_iter)->Call(arguments);
                if (cJSON* json_result = std::get_if<cJSON*>(&result)) {
                    char* json_str = cJSON_PrintUnformatted(*json_result);
                    if (json_str) {
                        std::string result_str(json_str);
                        free(json_str);
                        ReplyResult(id, result_str);
                    } else {
                        ReplyResult(id, "null");
                    }
                } else if (bool* bool_result = std::get_if<bool>(&result)) {
                    ReplyResult(id, *bool_result ? "true" : "false");
                } else {
                    ReplyResult(id, "null");
                }
            } catch (const std::exception& e) {
                ESP_LOGE(TAG, "tools/call: %s", e.what());
                ReplyError(id, e.what());
            }
        });
    } catch (const std::exception &e) {
        ESP_LOGE(TAG, "tools/call: %s", e.what());
        ReplyError(id, e.what());
        return;
    }
}

esp_err_t Ota::CheckVersion()
{
    auto http = SetupHttp();
    std::string url = GetCheckVersionUrl();

    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", url.c_str());
        return ESP_FAIL;
    }

    if (http->GetStatusCode() != 200)
    {
        ESP_LOGE(TAG, "HTTP request failed with status code: %d", http->GetStatusCode());
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty())
    {
        ESP_LOGE(TAG, "Empty response received");
        return ESP_FAIL;
    }

    cJSON *json = cJSON_Parse(response.c_str());
    if (!json)
    {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Check for errors in response
    cJSON *error_obj = cJSON_GetObjectItem(json, "error");
    if (error_obj)
    {
        ESP_LOGE(TAG, "Server returned error: %s", error_obj->valuestring);
        cJSON_Delete(json);
        return ESP_FAIL;
    }

    // Handle activation challenge if present
    cJSON *activation_challenge = cJSON_GetObjectItem(json, "activation_challenge");
    if (activation_challenge && cJSON_IsString(activation_challenge))
    {
        activation_challenge_ = std::string(activation_challenge->valuestring);
        has_activation_challenge_ = true;
        ESP_LOGI(TAG, "Received activation challenge");
    }

    // Handle MQTT configuration if present
    cJSON *mqtt_config = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_config && cJSON_IsObject(mqtt_config))
    {
        cJSON *host = cJSON_GetObjectItem(mqtt_config, "host");
        cJSON *port = cJSON_GetObjectItem(mqtt_config, "port");
        cJSON *username = cJSON_GetObjectItem(mqtt_config, "username");
        cJSON *password = cJSON_GetObjectItem(mqtt_config, "password");

        if (host && cJSON_IsString(host))
        {
            Settings mqtt_settings("mqtt", true);
            mqtt_settings.SetString("host", host->valuestring);

            if (port && cJSON_IsNumber(port))
            {
                mqtt_settings.SetInt("port", port->valueint);
            }

            if (username && cJSON_IsString(username))
            {
                mqtt_settings.SetString("username", username->valuestring);
            }

            if (password && cJSON_IsString(password))
            {
                mqtt_settings.SetString("password", password->valuestring);
            }

            mqtt_settings.Save();
            ESP_LOGI(TAG, "MQTT configuration updated");
        }
    }

    // Check for firmware update
    cJSON *latest_version = cJSON_GetObjectItem(json, "version");
    cJSON *firmware_url = cJSON_GetObjectItem(json, "url");

    if (!latest_version || !cJSON_IsString(latest_version))
    {
        ESP_LOGE(TAG, "Invalid response: missing version information");
        cJSON_Delete(json);
        return ESP_FAIL;
    }

    std::string current_version = esp_app_get_description()->version;
    std::string new_version = std::string(latest_version->valuestring);

    ESP_LOGI(TAG, "Current version: %s, Latest version: %s", current_version.c_str(), new_version.c_str());

    if (IsNewVersionAvailable(current_version, new_version))
    {
        if (firmware_url && cJSON_IsString(firmware_url))
        {
            firmware_url_ = std::string(firmware_url->valuestring);
            ESP_LOGI(TAG, "New firmware version available: %s", new_version.c_str());
            cJSON_Delete(json);
            return ESP_OK;
        }
        else
        {
            ESP_LOGE(TAG, "New version available but URL is missing");
            cJSON_Delete(json);
            return ESP_FAIL;
        }
    }
    else
    {
        ESP_LOGI(TAG, "Firmware is up to date");
        cJSON_Delete(json);
        return ESP_OK;
    }
}

bool Ota::Upgrade(const std::string &firmware_url, std::function<void(int progress, size_t speed)> callback)
{
    if (firmware_url.empty()) {
        ESP_LOGE(TAG, "Firmware URL is empty");
        return false;
    }

    ESP_LOGI(TAG, "Starting firmware upgrade from: %s", firmware_url.c_str());

    // Find OTA app partition
    const esp_partition_t *update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get next update partition");
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             update_partition->subtype, update_partition->address);

    // Begin OTA update
    esp_ota_handle_t update_handle = 0;
    esp_err_t err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Setup HTTP connection
    auto http = SetupHttp();
    if (!http->Open("GET", firmware_url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", firmware_url.c_str());
        esp_ota_end(update_handle);
        return false;
    }

    if (http->GetStatusCode() != 200) {
        ESP_LOGE(TAG, "HTTP GET failed, status code: %d", http->GetStatusCode());
        http->Close();
        esp_ota_end(update_handle);
        return false;
    }

    // Download and write firmware
    const size_t buffer_size = 4096;
    std::vector<uint8_t> buffer(buffer_size);
    size_t total_bytes_written = 0;
    size_t bytes_written_since_last_callback = 0;
    uint32_t last_callback_time = esp_log_timestamp();

    // Get content length for progress calculation
    size_t content_length = http->GetContentLength();
    bool use_progress = (content_length > 0);

    while (true) {
        ssize_t bytes_read = http->Read(buffer.data(), buffer_size);
        if (bytes_read < 0) {
            ESP_LOGE(TAG, "HTTP read error");
            http->Close();
            esp_ota_end(update_handle);
            return false;
        }

        if (bytes_read == 0) {
            // End of stream
            break;
        }

        err = esp_ota_write(update_handle, buffer.data(), bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            http->Close();
            esp_ota_end(update_handle);
            return false;
        }

        total_bytes_written += bytes_read;
        bytes_written_since_last_callback += bytes_read;

        // Call progress callback periodically (every 100ms or every 64KB)
        uint32_t current_time = esp_log_timestamp();
        if ((current_time - last_callback_time) >= 100 || bytes_written_since_last_callback >= (64 * 1024)) {
            int progress = 0;
            if (use_progress) {
                progress = (total_bytes_written * 100) / content_length;
                if (progress > 100) progress = 100;
            }

            size_t speed = 0;
            if ((current_time - last_callback_time) > 0) {
                speed = (bytes_written_since_last_callback * 1000) / (current_time - last_callback_time);
            }

            if (callback) {
                callback(progress, speed);
            }

            bytes_written_since_last_callback = 0;
            last_callback_time = current_time;
        }
    }

    http->Close();

    ESP_LOGI(TAG, "Total bytes written: %d", total_bytes_written);

    // Finish OTA update
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)", esp_err_to_name(err));
        return false;
    }

    // Validate firmware image
    esp_app_desc_t app_desc;
    err = esp_ota_get_partition_description(update_partition, &app_desc);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get partition description: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "New firmware version: %s", app_desc.version);

    // Set boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade completed successfully. Reboot required to apply changes.");
    return true;
}

std::string Ota::GetActivationPayload()
{
    if (!has_serial_number_)
    {
        return "{}";
    }

    std::string hmac_hex;
#ifdef SOC_HMAC_SUPPORTED
    uint8_t hmac_result[32]; // SHA-256 输出为32字节

    // 使用Key0计算HMAC
    esp_err_t ret = esp_hmac_calculate(HMAC_KEY0, (uint8_t *)activation_challenge_.data(), activation_challenge_.size(), hmac_result);
    if (ret != ESP_OK)
    {
        ESP_LOGE(TAG, "HMAC calculation failed: %s", esp_err_to_name(ret));
        return "{}";
    }

    for (size_t i = 0; i < sizeof(hmac_result); i++)
    {
        char buffer[3];
        sprintf(buffer, "%02x", hmac_result[i]);
        hmac_hex += buffer;
    }
#endif

    cJSON *payload = cJSON_CreateObject();
    cJSON_AddStringToObject(payload, "algorithm", "hmac-sha256");
    cJSON_AddStringToObject(payload, "serial_number", serial_number_.c_str());
    cJSON_AddStringToObject(payload, "challenge", activation_challenge_.c_str());
    cJSON_AddStringToObject(payload, "hmac", hmac_hex.c_str());
    auto json_str = cJSON_PrintUnformatted(payload);
    std::string json(json_str);
    cJSON_free(json_str);
    cJSON_Delete(payload);

    ESP_LOGI(TAG, "Activation payload: %s", json.c_str());
    return json;
}

esp_err_t Ota::Activate()
{
    // Check if we have activation code
    if (!has_activation_code_) {
        ESP_LOGE(TAG, "No activation code available");
        return ESP_ERR_INVALID_STATE;
    }

    // Construct activation URL using the activation code
    std::string url = GetCheckVersionUrl();
    // Remove any query parameters or path components and append activation endpoint
    size_t query_pos = url.find('?');
    if (query_pos != std::string::npos) {
        url = url.substr(0, query_pos);
    }

    // Ensure URL ends with '/' if needed
    if (!url.empty() && url.back() != '/') {
        url += '/';
    }
    url += "activate/" + activation_code_;

    ESP_LOGI(TAG, "Activating firmware with URL: %s", url.c_str());

    // Setup HTTP client
    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    // Prepare payload
    std::string payload = GetActivationPayload();
    http->SetContent(std::move(payload));

    // Open HTTP connection
    if (!http->Open("POST", url)) {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation, code=0x%x", last_error);
        return last_error;
    }

    // Check response status
    auto status_code = http->GetStatusCode();
    std::string response_data = http->ReadAll();
    http->Close();

    ESP_LOGI(TAG, "Activation response status: %d, data: %s", status_code, response_data.c_str());

    // Handle response
    if (status_code == 200 || status_code == 204) {
        ESP_LOGI(TAG, "Activation successful");
        return ESP_OK;
    } else if (status_code == 400) {
        ESP_LOGE(TAG, "Bad request during activation");
        return ESP_ERR_INVALID_ARG;
    } else if (status_code == 401 || status_code == 403) {
        ESP_LOGE(TAG, "Unauthorized during activation");
        return ESP_ERR_INVALID_STATE;
    } else if (status_code >= 500) {
        ESP_LOGE(TAG, "Server error during activation");
        return ESP_ERR_HTTP_SERVER_ERROR;
    } else {
        ESP_LOGE(TAG, "Activation failed with status code: %d", status_code);
        return ESP_FAIL;
    }
}

esp_err_t SystemInfo::PrintTaskCpuUsage(TickType_t xTicksToWait)
{
    TaskStatus_t *pxTaskStatusArray_initial;
    TaskStatus_t *pxTaskStatusArray_final;
    volatile UBaseType_t uxArraySize_initial, uxArraySize_final;
    uint32_t ulTotalRunTime_initial, ulTotalRunTime_final;
    uint32_t ulRunTimeDifference;
    uint32_t ulTotalRunTimeDifference;
    float fUsagePercent;

    // Take initial snapshot
    uxArraySize_initial = uxTaskGetNumberOfTasks();
    pxTaskStatusArray_initial = (TaskStatus_t*)malloc(uxArraySize_initial * sizeof(TaskStatus_t));
    if (pxTaskStatusArray_initial == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for initial task status array");
        return ESP_ERR_NO_MEM;
    }

    uxArraySize_initial = uxTaskGetSystemState(pxTaskStatusArray_initial, uxArraySize_initial, &ulTotalRunTime_initial);
    if (uxArraySize_initial == 0) {
        ESP_LOGE(TAG, "Failed to get initial task state");
        free(pxTaskStatusArray_initial);
        return ESP_FAIL;
    }

    // Wait for specified time
    vTaskDelay(xTicksToWait);

    // Take final snapshot
    uxArraySize_final = uxTaskGetNumberOfTasks();
    pxTaskStatusArray_final = (TaskStatus_t*)malloc(uxArraySize_final * sizeof(TaskStatus_t));
    if (pxTaskStatusArray_final == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for final task status array");
        free(pxTaskStatusArray_initial);
        return ESP_ERR_NO_MEM;
    }

    uxArraySize_final = uxTaskGetSystemState(pxTaskStatusArray_final, uxArraySize_final, &ulTotalRunTime_final);
    if (uxArraySize_final == 0) {
        ESP_LOGE(TAG, "Failed to get final task state");
        free(pxTaskStatusArray_initial);
        free(pxTaskStatusArray_final);
        return ESP_FAIL;
    }

    // Calculate total run time difference
    ulTotalRunTimeDifference = ulTotalRunTime_final - ulTotalRunTime_initial;

    if (ulTotalRunTimeDifference == 0) {
        ESP_LOGW(TAG, "No run time difference detected");
        free(pxTaskStatusArray_initial);
        free(pxTaskStatusArray_final);
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "Task CPU Usage over %lu ticks:", xTicksToWait);

    // Compare tasks and calculate usage
    for (UBaseType_t x = 0; x < uxArraySize_initial; x++) {
        bool task_found = false;
        for (UBaseType_t y = 0; y < uxArraySize_final; y++) {
            if (pxTaskStatusArray_initial[x].xHandle == pxTaskStatusArray_final[y].xHandle) {
                task_found = true;
                ulRunTimeDifference = pxTaskStatusArray_final[y].ulRunTimeCounter - pxTaskStatusArray_initial[x].ulRunTimeCounter;
                fUsagePercent = (float)(ulRunTimeDifference * 100.0) / (float)ulTotalRunTimeDifference;

                ESP_LOGI(TAG, "Task: %-16s CPU: %6.2f%% State: %d",
                         pxTaskStatusArray_initial[x].pcTaskName,
                         fUsagePercent,
                         pxTaskStatusArray_initial[x].eCurrentState);
                break;
            }
        }
        if (!task_found) {
            ESP_LOGI(TAG, "Task: %-16s was deleted during measurement",
                     pxTaskStatusArray_initial[x].pcTaskName);
        }
    }

    // Check for newly created tasks
    for (UBaseType_t y = 0; y < uxArraySize_final; y++) {
        bool task_found = false;
        for (UBaseType_t x = 0; x < uxArraySize_initial; x++) {
            if (pxTaskStatusArray_initial[x].xHandle == pxTaskStatusArray_final[y].xHandle) {
                task_found = true;
                break;
            }
        }
        if (!task_found) {
            ESP_LOGI(TAG, "Task: %-16s was created during measurement",
                     pxTaskStatusArray_final[y].pcTaskName);
        }
    }

    free(pxTaskStatusArray_initial);
    free(pxTaskStatusArray_final);

    return ESP_OK;
}

void AudioService::Initialize(AudioCodec *codec)
{
    codec_ = codec;

    // Initialize Opus encoder and decoder
    opus_encoder_ = std::make_unique<OpusEncoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);
    opus_decoder_ = std::make_unique<OpusDecoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);

    // Configure resamplers
    if (codec_->input_sample_rate() != 16000) {
        input_resampler_.Configure(codec_->input_sample_rate(), 16000);
        if (codec_->input_channels() == 2) {
            reference_resampler_.Configure(codec_->input_sample_rate(), 16000);
        }
    }

    if (codec_->output_sample_rate() != 16000) {
        output_resampler_.Configure(16000, codec_->output_sample_rate());
    }

    // Initialize audio processor
    audio_processor_ = std::make_unique<
#if CONFIG_USE_AUDIO_PROCESSOR
        AfeAudioProcessor
#else
        NoAudioProcessor
#endif
    >();

    // Create audio power timer
    esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            AudioService* service = static_cast<AudioService*>(arg);
            service->CheckAndUpdateAudioPowerState();
        },
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "audio_power_timer"
    };
    esp_timer_create(&timer_args, &audio_power_timer_);

    // Initialize queues
    audio_encode_queue_.clear();
    audio_decode_queue_.clear();
    audio_playback_queue_.clear();
    audio_testing_queue_.clear();
    audio_send_queue_.clear();
    timestamp_queue_.clear();
}

void AudioService::Start()
{
    service_stopped_ = false;
    xEventGroupClearBits(event_group_, AS_EVENT_AUDIO_TESTING_RUNNING | AS_EVENT_WAKE_WORD_RUNNING | AS_EVENT_AUDIO_PROCESSOR_RUNNING);

    esp_timer_start_periodic(audio_power_timer_, 1000000);

#if CONFIG_USE_AUDIO_PROCESSOR
    /* Start the audio input task */
    xTaskCreatePinnedToCore([](void *arg)
                            {
        AudioService* audio_service = (AudioService*)arg;
        audio_service->AudioInputTask();
        vTaskDelete(NULL); }, "audio_input", 2048 * 3, this, 8, &audio_input_task_handle_, 0);

    /* Start the audio output task */
    xTaskCreate([](void *arg)
                {
        AudioService* audio_service = (AudioService*)arg;
        audio_service->AudioOutputTask();
        vTaskDelete(NULL); }, "audio_output", 2048 * 2, this, 4, &audio_output_task_handle_);
#else
    /* Start the audio input task */
    xTaskCreate([](void *arg)
                {
        AudioService* audio_service = (AudioService*)arg;
        audio_service->AudioInputTask();
        vTaskDelete(NULL); }, "audio_input", 2048 * 2, this, 8, &audio_input_task_handle_);

    /* Start the audio output task */
    xTaskCreate([](void *arg)
                {
        AudioService* audio_service = (AudioService*)arg;
        audio_service->AudioOutputTask();
        vTaskDelete(NULL); }, "audio_output", 2048, this, 4, &audio_output_task_handle_);
#endif

    /* Start the opus codec task */
    xTaskCreate([](void *arg)
                {
        AudioService* audio_service = (AudioService*)arg;
        audio_service->OpusCodecTask();
        vTaskDelete(NULL); }, "opus_codec", 2048 * 2, this, 5, &opus_codec_task_handle_);
}

bool AudioService::ReadAudioData(std::vector<int16_t> &data, int target_sample_rate, int samples)
{
    /* Enable audio input if it's not enabled */
    if (!codec_->input_enabled())
    {
        esp_timer_stop(audio_power_timer_);
        esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
        codec_->EnableInput(true);

        /* Warm up the audio input if needed */
        if (audio_input_need_warmup_)
        {
            int warmup_samples = std::min(samples * 4, 16000);
            std::vector<int16_t> warmup_data(warmup_samples * codec_->input_channels());
            for (int i = 0; i < 4 && !service_stopped_; i++)
            {
                if (!codec_->InputData(warmup_data))
                {
                    ESP_LOGW(TAG, "Failed to read warmup audio data");
                }
            }
            audio_input_need_warmup_ = false;
        }
    }

    /* Check if we need to resample */
    bool need_resample = (codec_->input_sample_rate() != target_sample_rate);
    if (need_resample)
    {
        input_resampler_.Configure(codec_->input_sample_rate(), target_sample_rate);
        if (codec_->input_channels() == 2)
        {
            reference_resampler_.Configure(codec_->input_sample_rate(), target_sample_rate);
        }
    }

    if (need_resample)
    {
        std::vector<int16_t> raw_data(samples * codec_->input_channels());
        if (!codec_->InputData(raw_data))
        {
            return false;
        }

        if (codec_->input_channels() == 2)
        {
            /* Split stereo channels */
            std::vector<int16_t> mic_channel(samples);
            std::vector<int16_t> reference_channel(samples);
            for (size_t i = 0, j = 0; i < samples; ++i, j += 2)
            {
                mic_channel[i] = raw_data[j];
                reference_channel[i] = raw_data[j + 1];
            }

            /* Resample both channels */
            auto resampled_mic = std::vector<int16_t>(input_resampler_.GetOutputSamples(mic_channel.size()));
            auto resampled_reference = std::vector<int16_t>(reference_resampler_.GetOutputSamples(reference_channel.size()));
            input_resampler_.Process(mic_channel.data(), mic_channel.size(), resampled_mic.data());
            reference_resampler_.Process(reference_channel.data(), reference_channel.size(), resampled_reference.data());

            /* Merge resampled channels */
            data.resize(resampled_mic.size() + resampled_reference.size());
            for (size_t i = 0, j = 0; i < resampled_mic.size(); ++i, j += 2)
            {
                data[j] = resampled_mic[i];
                data[j + 1] = resampled_reference[i];
            }
        }
        else
        {
            /* Mono resampling */
            auto resampled = std::vector<int16_t>(input_resampler_.GetOutputSamples(raw_data.size()));
            input_resampler_.Process(raw_data.data(), raw_data.size(), resampled.data());
            data = std::move(resampled);
        }
    }
    else
    {
        /* No resampling needed */
        data.resize(samples * codec_->input_channels());
        if (!codec_->InputData(data))
        {
            return false;
        }
    }

    /* Update the last input time */
    last_input_time_ = std::chrono::steady_clock::now();
    debug_statistics_.input_count++;

#if CONFIG_USE_AUDIO_DEBUGGER
    /* Audio debugging: send raw audio data */
    if (audio_debugger_ == nullptr)
    {
        audio_debugger_ = std::make_unique<AudioDebugger>();
    }
    audio_debugger_->Feed(data);
#endif

    return true;
}

void AudioService::AudioInputTask()
{
    const int kFrameDurationMs = OPUS_FRAME_DURATION_MS;
    const int kSampleRate = 16000;
    const int kChannels = 1;
    const int kSamplesPerFrame = kSampleRate * kFrameDurationMs / 1000 * kChannels;

    std::vector<int16_t> audio_data;
    int warmup_frames = 0;
    const int kWarmupFrames = 5; // 100ms warmup

    while (!service_stopped_)
    {
        EventBits_t bits = xEventGroupGetBits(event_group_);

        // Check if any audio processing is enabled
        bool audio_testing_running = (bits & AS_EVENT_AUDIO_TESTING_RUNNING);
        bool wake_word_running = (bits & AS_EVENT_WAKE_WORD_RUNNING);
        bool audio_processor_running = (bits & AS_EVENT_AUDIO_PROCESSOR_RUNNING);

        // If no audio processing is active, wait and continue
        if (!audio_testing_running && !wake_word_running && !audio_processor_running)
        {
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Read audio data at 16kHz
        if (!ReadAudioData(audio_data, kSampleRate, kSamplesPerFrame))
        {
            vTaskDelay(pdMS_TO_TICKS(1));
            continue;
        }

        // Handle warmup period for audio input
        if (audio_input_need_warmup_)
        {
            warmup_frames++;
            if (warmup_frames >= kWarmupFrames)
            {
                audio_input_need_warmup_ = false;
                warmup_frames = 0;
            }
            else
            {
                continue;
            }
        }

        // Route audio data based on current mode
        if (audio_testing_running)
        {
            // Feed to audio testing queue
            PushTaskToEncodeQueue(kAudioTaskTypeEncodeToTestingQueue, std::move(audio_data));
        }
        else if (wake_word_running && wake_word_)
        {
            // Feed to wake word detection
            wake_word_->FeedAudioData(audio_data);
        }
        else if (audio_processor_running)
        {
            // Feed to audio processor
            if (voice_detected_)
            {
                // When voice is detected, feed to both reference and mic
                audio_processor_->FeedReferenceData(audio_data);
                audio_processor_->FeedMicData(audio_data);
            }
            else
            {
                // When no voice detected, only feed mic data for VAD
                audio_processor_->FeedMicData(audio_data);
            }
        }

        // Small delay to maintain timing
        vTaskDelay(pdMS_TO_TICKS(1));
    }

    ESP_LOGW(TAG, "Audio input task stopped");
}

void AudioService::AudioOutputTask()
{
    while (true)
    {
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);
        audio_queue_cv_.wait(lock, [this]()
                             { return service_stopped_ || !audio_playback_queue_.empty(); });

        if (service_stopped_)
        {
            break;
        }

        auto task = std::move(audio_playback_queue_.front());
        audio_playback_queue_.pop_front();
        audio_queue_cv_.notify_all();
        lock.unlock();

        // Enable output if not already enabled
        if (!codec_->output_enabled())
        {
            esp_timer_stop(audio_power_timer_);
            esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
            codec_->EnableOutput(true);
        }

        // Handle timestamp for AEC
        if (task->timestamp > 0)
        {
            std::lock_guard<std::mutex> timestamp_lock(timestamp_queue_mutex_);
            timestamp_queue_.push_back(task->timestamp);
        }

        // Output the audio data
        if (!codec_->OutputData(task->pcm))
        {
            ESP_LOGE(TAG, "Failed to output audio data");
        }

        // Update last output time for power management
        last_output_time_ = std::chrono::steady_clock::now();
        debug_statistics_.output_count++;
    }

    ESP_LOGW(TAG, "Audio output task stopped");
}

void AudioService::OpusCodecTask()
{
    while (true)
    {
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);
        audio_queue_cv_.wait(lock, [this]()
                             { return !audio_encode_queue_.empty() || !audio_decode_queue_.empty() || service_stopped_; });

        if (service_stopped_)
        {
            break;
        }

        // Process encoding tasks first
        if (!audio_encode_queue_.empty())
        {
            auto task = std::move(audio_encode_queue_.front());
            audio_encode_queue_.pop_front();
            audio_queue_cv_.notify_all();
            lock.unlock();

            switch (task->type)
            {
                case kAudioTaskTypeEncodeToSendQueue:
                {
                    auto packet = std::make_unique<AudioStreamPacket>();
                    packet->sample_rate = opus_encoder_->sample_rate();
                    packet->frame_duration = opus_encoder_->duration_ms();

                    if (opus_encoder_->Encode(task->pcm, packet->payload))
                    {
                        std::lock_guard<std::mutex> send_lock(audio_queue_mutex_);
                        audio_send_queue_.push_back(std::move(packet));
                        audio_queue_cv_.notify_all();
                    }
                    break;
                }

                case kAudioTaskTypeEncodeToTestingQueue:
                {
                    auto packet = std::make_unique<AudioStreamPacket>();
                    packet->sample_rate = opus_encoder_->sample_rate();
                    packet->frame_duration = opus_encoder_->duration_ms();

                    if (opus_encoder_->Encode(task->pcm, packet->payload))
                    {
                        std::lock_guard<std::mutex> test_lock(audio_queue_mutex_);
                        audio_testing_queue_.push_back(std::move(packet));
                        audio_queue_cv_.notify_all();
                    }
                    break;
                }
            }
        }
        // Process decoding tasks
        else if (!audio_decode_queue_.empty())
        {
            auto packet = std::move(audio_decode_queue_.front());
            audio_decode_queue_.pop_front();
            audio_queue_cv_.notify_all();
            lock.unlock();

            // Set decoder sample rate if needed
            SetDecodeSampleRate(packet->sample_rate, packet->frame_duration);

            auto pcm_data = std::vector<int16_t>();
            if (opus_decoder_->Decode(packet->payload, pcm_data))
            {
                auto playback_task = std::make_unique<AudioTask>();
                playback_task->timestamp = packet->timestamp;

                // Resample if needed
                if (opus_decoder_->sample_rate() != codec_->output_sample_rate())
                {
                    auto resampled = std::vector<int16_t>(output_resampler_.GetOutputSamples(pcm_data.size()));
                    output_resampler_.Process(pcm_data.data(), pcm_data.size(), resampled.data());
                    playback_task->pcm = std::move(resampled);
                }
                else
                {
                    playback_task->pcm = std::move(pcm_data);
                }

                // Add to playback queue
                std::unique_lock<std::mutex> playback_lock(audio_queue_mutex_);
                audio_queue_cv_.wait(playback_lock, [this]()
                                     { return audio_playback_queue_.size() < MAX_PLAYBACK_TASKS_IN_QUEUE; });
                audio_playback_queue_.push_back(std::move(playback_task));
                audio_queue_cv_.notify_all();
            }
        }
    }

    ESP_LOGW(TAG, "Opus codec task stopped");
}

void AudioService::PushTaskToEncodeQueue(AudioTaskType type, std::vector<int16_t> &&pcm)
{
    auto task = std::make_unique<AudioTask>();
    task->type = type;
    task->pcm = std::move(pcm);

    /* Push the task to the encode queue */
    std::unique_lock<std::mutex> lock(audio_queue_mutex_);

    /* If the task is to send queue, we need to set the timestamp */
    if (type == kAudioTaskTypeEncodeToSendQueue && !timestamp_queue_.empty())
    {
        if (timestamp_queue_.size() <= MAX_TIMESTAMPS_IN_QUEUE)
        {
            task->timestamp = timestamp_queue_.front();
            timestamp_queue_.pop_front();
        }
        else
        {
            ESP_LOGW(TAG, "Timestamp queue (%u) is full, dropping timestamp", timestamp_queue_.size());
            if (!timestamp_queue_.empty()) {
                timestamp_queue_.pop_front();
            }
        }
    }

    /* Wait until there is space in the queue */
    audio_queue_cv_.wait(lock, [this]()
                         { return audio_encode_queue_.size() < MAX_ENCODE_TASKS_IN_QUEUE || service_stopped_; });

    if (service_stopped_) {
        return;
    }

    audio_encode_queue_.push_back(std::move(task));
    audio_queue_cv_.notify_all();
}

void AudioService::EnableWakeWordDetection(bool enable)
{
    ESP_LOGD(TAG, "%s wake word detection", enable ? "Enabling" : "Disabling");
    if (enable)
    {
        if (wake_word_)
        {
            /* We should make sure no audio is playing */
            ResetDecoder();
            audio_input_need_warmup_ = true;
            wake_word_->Start();
            xEventGroupSetBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
        }
    }
    else
    {
        if (wake_word_)
        {
            wake_word_->Stop();
        }
        xEventGroupClearBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);
    }
}

void AudioService::PlaySound(const std::string_view &ogg)
{
    if (ogg.empty()) {
        ESP_LOGW(TAG, "Empty OGG data provided");
        return;
    }

    // Enable audio output if it's disabled
    if (!codec_->output_enabled()) {
        esp_timer_stop(audio_power_timer_);
        esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
        codec_->EnableOutput(true);
    }

    // Simple OGG parser for Opus files
    const uint8_t* data = reinterpret_cast<const uint8_t*>(ogg.data());
    size_t data_size = ogg.size();
    size_t offset = 0;

    // Look for OGG capture pattern
    while (offset + 4 <= data_size) {
        // Check for OGG page header (OggS)
        if (data[offset] == 'O' && data[offset+1] == 'g' && data[offset+2] == 'g' && data[offset+3] == 'S') {
            if (offset + 27 > data_size) {
                break;
            }

            // Parse OGG page header
            uint8_t header_type = data[offset + 5];
            uint32_t granule_pos = *reinterpret_cast<const uint32_t*>(&data[offset + 6]);
            uint32_t bitstream_serial = *reinterpret_cast<const uint32_t*>(&data[offset + 14]);
            uint32_t page_seq_num = *reinterpret_cast<const uint32_t*>(&data[offset + 18]);
            uint8_t segments_count = data[offset + 26];

            if (offset + 27 + segments_count > data_size) {
                break;
            }

            // Calculate page payload start
            size_t segment_table_offset = offset + 27;
            size_t payload_offset = segment_table_offset + segments_count;

            // Calculate total payload size
            size_t payload_size = 0;
            for (int i = 0; i < segments_count; i++) {
                payload_size += data[segment_table_offset + i];
            }

            if (payload_offset + payload_size > data_size) {
                break;
            }

            // Check if this is the first page (might contain Opus header)
            if (header_type & 0x02) { // Beginning of stream
                // Look for Opus header in the first packet
                if (payload_size >= 19 && memcmp(&data[payload_offset], "OpusHead", 8) == 0) {
                    // Parse Opus header
                    uint32_t sample_rate = *reinterpret_cast<const uint32_t*>(&data[payload_offset + 12]);

                    // Configure decoder for this sample rate if needed
                    SetDecodeSampleRate(sample_rate, OPUS_FRAME_DURATION_MS);
                }
            } else {
                // Regular audio data page - decode and play
                // For simplicity, we'll treat the entire payload as one Opus packet
                if (payload_size > 0) {
                    auto packet = std::make_unique<AudioStreamPacket>();
                    packet->payload.assign(&data[payload_offset], &data[payload_offset + payload_size]);
                    packet->sample_rate = opus_decoder_->sample_rate();
                    packet->frame_duration = OPUS_FRAME_DURATION_MS;

                    std::vector<int16_t> pcm_data;
                    if (opus_decoder_->Decode(std::move(packet->payload), pcm_data)) {
                        // Resample if needed
                        if (opus_decoder_->sample_rate() != codec_->output_sample_rate()) {
                            int target_size = output_resampler_.GetOutputSamples(pcm_data.size());
                            std::vector<int16_t> resampled(target_size);
                            output_resampler_.Process(pcm_data.data(), pcm_data.size(), resampled.data());
                            codec_->OutputData(resampled);
                        } else {
                            codec_->OutputData(pcm_data);
                        }

                        // Update last output time for power management
                        last_output_time_ = std::chrono::steady_clock::now();
                        debug_statistics_.playback_count++;
                    }
                }
            }

            offset = payload_offset + payload_size;
        } else {
            offset++;
        }
    }
}

void AudioService::SetModelsList(srmodel_list_t *models_list)
{
    models_list_ = models_list;

    if (!models_list_ || models_list_->num_models == 0) {
        ESP_LOGW(TAG, "No models provided, wake word detection disabled");
        wake_word_ = nullptr;
        return;
    }

    // Select appropriate wake word engine based on models and target hardware
    bool use_custom_wake_word = false;
    bool use_afe_wake_word = false;

    // Check if any model has custom wake word prefix
    for (int i = 0; i < models_list_->num_models; i++) {
        if (strncmp(models_list_->models[i].name, "custom_", 7) == 0) {
            use_custom_wake_word = true;
            break;
        }
        if (strncmp(models_list_->models[i].name, "afe_", 4) == 0) {
            use_afe_wake_word = true;
            break;
        }
    }

#if CONFIG_IDF_TARGET_ESP32S3 || CONFIG_IDF_TARGET_ESP32P4
    if (use_custom_wake_word) {
        wake_word_ = std::make_unique<CustomWakeWord>();
        ESP_LOGI(TAG, "Using Custom Wake Word engine");
    } else if (use_afe_wake_word) {
        wake_word_ = std::make_unique<AfeWakeWord>();
        ESP_LOGI(TAG, "Using AFE Wake Word engine");
    } else {
        wake_word_ = std::make_unique<AfeWakeWord>();
        ESP_LOGI(TAG, "Using default AFE Wake Word engine");
    }
#else
    // For other targets, use ESP wake word
    wake_word_ = std::make_unique<EspWakeWord>();
    ESP_LOGI(TAG, "Using ESP Wake Word engine");
#endif

    // Register wake word detection callback
    if (wake_word_) {
        wake_word_->OnWakeWordDetected([this](const std::string &wake_word) {
            if (callbacks_.on_wake_word_detected) {
                callbacks_.on_wake_word_detected(wake_word);
            }
        });
    }
}

Es8388AudioCodec::Es8388AudioCodec(void* i2c_master_handle, i2c_port_t i2c_port, int input_sample_rate, int output_sample_rate,
                                   gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din, gpio_num_t pa_pin,
                                   uint8_t address, bool input_reference)
    : input_sample_rate_(input_sample_rate)
    , output_sample_rate_(output_sample_rate)
    , input_channels_(input_reference ? 2 : 1)
    , output_channels_(1)
    , pa_pin_(pa_pin)
    , input_reference_(input_reference)
    , input_gain_(0)
    , output_volume_(50)
    , input_enabled_(false)
    , output_enabled_(false)
    , tx_handle_(nullptr)
    , rx_handle_(nullptr)
    , ctrl_if_(nullptr)
    , codec_if_(nullptr)
    , gpio_if_(nullptr)
    , data_if_(nullptr)
    , input_dev_(nullptr)
    , output_dev_(nullptr)
{
    // Create I2C control interface
    audio_codec_i2c_cfg_t i2c_cfg = {
        .port = i2c_port,
        .addr = address,
        .bus_handle = (i2c_master_bus_handle_t)i2c_master_handle,
    };
    ctrl_if_ = audio_codec_new_i2c_ctrl(&i2c_cfg);

    // Create ES8388 codec interface
    codec_if_ = es8388_codec_new(ctrl_if_);

    // Create GPIO interface for power amplifier control
    if (pa_pin_ != GPIO_NUM_NC) {
        audio_codec_gpio_cfg_t gpio_cfg = {
            .gpio_intr_type = GPIO_INTR_DISABLE,
            .gpio_pull_down = false,
            .gpio_pull_up = false,
            .gpio_mode = GPIO_MODE_OUTPUT,
        };
        gpio_if_ = audio_codec_new_gpio();
        gpio_if_->setup(gpio_if_, (int)pa_pin_, &gpio_cfg);
        gpio_set_level(pa_pin_, 0);
    }

    // Create data interface
    data_if_ = audio_codec_new_i2s_data(I2S_NUM_0);

    // Create input device
    input_dev_ = esp_codec_dev_new(codec_if_, ctrl_if_, data_if_, gpio_if_);
    if (input_dev_) {
        esp_codec_dev_set_role(input_dev_, ESP_CODEC_DEV_TYPE_IN);
    }

    // Create output device
    output_dev_ = esp_codec_dev_new(codec_if_, ctrl_if_, data_if_, gpio_if_);
    if (output_dev_) {
        esp_codec_dev_set_role(output_dev_, ESP_CODEC_DEV_TYPE_OUT);
    }

    // Create duplex channels
    CreateDuplexChannels(mclk, bclk, ws, dout, din);
}

void Es8388AudioCodec::CreateDuplexChannels(gpio_num_t mclk, gpio_num_t bclk, gpio_num_t ws, gpio_num_t dout, gpio_num_t din)
{
    // Configure I2S TX channel (output)
    i2s_chan_config_t tx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    tx_chan_cfg.auto_clear = true;
    ESP_ERROR_CHECK(i2s_new_channel(&tx_chan_cfg, &tx_handle_, NULL));

    // Configure I2S RX channel (input)
    i2s_chan_config_t rx_chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_NUM_0, I2S_ROLE_MASTER);
    ESP_ERROR_CHECK(i2s_new_channel(&rx_chan_cfg, NULL, &rx_handle_));

    // Configure I2S common settings
    i2s_std_config_t std_cfg = {
        .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(input_sample_rate_),
        .slot_cfg = I2S_STD_PHILIPS_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, I2S_SLOT_MODE_STEREO),
        .gpio_cfg = {
            .mclk = mclk,
            .bclk = bclk,
            .ws = ws,
            .dout = dout,
            .din = din,
            .invert_flags = {
                .mclk_inv = false,
                .bclk_inv = false,
                .ws_inv = false,
            },
        },
    };

    // Apply configuration to both channels
    ESP_ERROR_CHECK(i2s_channel_init_std_mode(tx_handle_, &std_cfg));
    ESP_ERROR_CHECK(i2s_channel_init_std_mode(rx_handle_, &std_cfg));
}

void Es8388AudioCodec::EnableInput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == input_enabled_)
    {
        return;
    }
    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = (uint32_t)input_channels_,
            .channel_mask = 0,
            .sample_rate = (uint32_t)input_sample_rate_,
            .mclk_multiple = 0,
        };
        ESP_ERROR_CHECK(esp_codec_dev_open(input_dev_, &fs));

        // Set input gain
        ESP_ERROR_CHECK(esp_codec_dev_set_in_gain(input_dev_, input_gain_));

        // Additional ES8388 specific register configuration for input
        if (input_reference_)
        {
            // Configure for reference input (stereo mode for echo cancellation)
            uint8_t reg_val = 0x00; // Example value, actual depends on ES8388 datasheet
            ctrl_if_->write_reg(ctrl_if_, 0x08, 1, &reg_val, 1); // ADC Control Reg 1
            ctrl_if_->write_reg(ctrl_if_, 0x09, 1, &reg_val, 1); // ADC Control Reg 2
        }
        else
        {
            // Configure for single microphone input
            uint8_t reg_val = 0x00; // Example value
            ctrl_if_->write_reg(ctrl_if_, 0x08, 1, &reg_val, 1);
        }
    }
    else
    {
        ESP_ERROR_CHECK(esp_codec_dev_close(input_dev_));
    }
    AudioCodec::EnableInput(enable);
}

void Es8388AudioCodec::EnableOutput(bool enable)
{
    std::lock_guard<std::mutex> lock(data_if_mutex_);
    if (enable == output_enabled_)
    {
        return;
    }
    if (enable)
    {
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = 1,
            .channel_mask = 0,
            .sample_rate = (uint32_t)output_sample_rate_,
            .mclk_multiple = 0,
        };
        ESP_ERROR_CHECK(esp_codec_dev_open(output_dev_, &fs));
        ESP_ERROR_CHECK(esp_codec_dev_set_out_vol(output_dev_, output_volume_));

        // Set analog output volume to 0dB, default is -45dB
        uint8_t reg_val = 30; // 0dB
        if (input_reference_)
        {
            reg_val = 27;
        }
        uint8_t regs[] = {46, 47, 48, 49}; // HP_LVOL, HP_RVOL, SPK_LVOL, SPK_RVOL
        for (uint8_t reg : regs)
        {
            ctrl_if_->write_reg(ctrl_if_, reg, 1, &reg_val, 1);
        }

        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_set_level(pa_pin_, 1);
        }
    }
    else
    {
        ESP_ERROR_CHECK(esp_codec_dev_close(output_dev_));
        if (pa_pin_ != GPIO_NUM_NC)
        {
            gpio_set_level(pa_pin_, 0);
        }
    }
    AudioCodec::EnableOutput(enable);
}

AudioDebugger::AudioDebugger()
    : udp_sockfd_(-1)
{
#if CONFIG_USE_AUDIO_DEBUGGER
    // Create UDP socket
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_sockfd_ < 0)
    {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return;
    }

    // Zero out server address structure
    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));

    // Setup server address
    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(CONFIG_AUDIO_DEBUG_UDP_PORT);

    // Convert IP address string to binary form
    if (inet_aton(CONFIG_AUDIO_DEBUG_UDP_SERVER, &udp_server_addr_.sin_addr) == 0)
    {
        ESP_LOGE(TAG, "Invalid server IP address: %s", CONFIG_AUDIO_DEBUG_UDP_SERVER);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "Initialized UDP socket to %s:%d", CONFIG_AUDIO_DEBUG_UDP_SERVER, CONFIG_AUDIO_DEBUG_UDP_PORT);
#endif
}

bool AfeWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    audio_codec_ = codec;
    models_ = models_list;

    // Load wake word models
    auto models = esp_srmodel_init(models_);
    if (models == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize speech recognition models");
        return false;
    }

    // Get wake word model names
    int wake_word_num = esp_srmodel_get_wakenet_model_num(models);
    wake_words_.resize(wake_word_num);
    for (int i = 0; i < wake_word_num; i++) {
        wake_words_[i] = esp_srmodel_get_wakenet_model_name(models, i + 1);
        ESP_LOGI(TAG, "Loaded wake word model: %s", wake_words_[i].c_str());
    }

    // Initialize AFE interface
    afe_config_t afe_config = {
        .aec_en = false,
        .se_en = false,
        .vad_en = true,
        .wakenet_en = true,
        .voice_communication_agc_en = false,
        .voice_communication_agc_gain = 0,
        .voice_detection_agc_en = true,
        .voice_detection_agc_gain = 15,
        .vad_mode = VAD_MODE_3,
        .wakenet_model_name = wake_words_[0].c_str(),
        .wakenet_mode = DET_MODE_3,
        .afe_linear_gain = 1.0,
        .afe_mode = SRMODE_LOW_COST,
        .afe_perferred_core = 0,
        .afe_perferred_priority = 5,
        .malloc_place = AFE_Malloc_Spiram,
        .agc_mode = AFE_MN_PEAK_AGC_MODE_3,
        .pcm_config = {
            .total_ch_num = 1,
            .mic_num = 1,
            .ref_num = 0,
            .sample_rate = 16000,
        }
    };

    afe_data_ = afe_init(&afe_config);
    if (afe_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to initialize AFE");
        return false;
    }

    afe_iface_ = afe_get_interface();
    if (afe_iface_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get AFE interface");
        return false;
    }

    // Create audio detection task
    const size_t stack_size = 4096 * 2;
    audio_detection_task_stack_ = (StackType_t *)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
    if (audio_detection_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate audio detection task stack");
        return false;
    }

    audio_detection_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
    if (audio_detection_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate audio detection task buffer");
        return false;
    }

    audio_detection_task_ = xTaskCreateStatic([](void *arg) {
        auto this_ = (AfeWakeWord*)arg;
        this_->AudioDetectionTask();
        vTaskDelete(NULL);
    }, "afe_detect", stack_size, this, 5, audio_detection_task_stack_, audio_detection_task_buffer_);

    if (audio_detection_task_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create audio detection task");
        return false;
    }

    ESP_LOGI(TAG, "AFE wake word detection initialized successfully");
    return true;
}

void AfeWakeWord::AudioDetectionTask()
{
    auto fetch_size = afe_iface_->get_fetch_chunksize(afe_data_);
    auto feed_size = afe_iface_->get_feed_chunksize(afe_data_);
    ESP_LOGI(TAG, "Audio detection task started, feed size: %d fetch size: %d",
             feed_size, fetch_size);

    while (true)
    {
        EventBits_t uxBits = xEventGroupWaitBits(event_group_, 
                                               DETECTION_RUNNING_EVENT, 
                                               pdFALSE, 
                                               pdTRUE, 
                                               portMAX_DELAY);

        if (!(uxBits & DETECTION_RUNNING_EVENT)) {
            continue;
        }

        auto res = afe_iface_->fetch_with_delay(afe_data_, portMAX_DELAY);
        if (res == nullptr || res->ret_value == ESP_FAIL)
        {
            continue;
        }

        // Store the wake word data for voice recognition, like who is speaking
        StoreWakeWordData(res->data, res->data_size / sizeof(int16_t));

        if (res->wakeup_state == WAKENET_DETECTED)
        {
            Stop();
            last_detected_wake_word_ = wake_words_[res->wakenet_model_index - 1];

            if (wake_word_detected_callback_)
            {
                wake_word_detected_callback_(last_detected_wake_word_);
            }
        }
    }
}

void AfeWakeWord::EncodeWakeWordData()
{
    // Allocate stack for the encoding task (use SPIRAM if available)
    wake_word_encode_task_stack_ = (StackType_t *)heap_caps_malloc(4096 * sizeof(StackType_t), MALLOC_CAP_SPIRAM);
    if (wake_word_encode_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate stack for wake word encode task");
        return;
    }

    // Allocate task buffer (use internal memory for better performance)
    wake_word_encode_task_buffer_ = (StaticTask_t *)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    if (wake_word_encode_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate task buffer for wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return;
    }

    // Create the encoding task
    encode_task_handle_ = xTaskCreateStatic(
        [](void *arg) {
            auto this_ = (AfeWakeWord *)arg;
            this_->EncodeTask();
            vTaskDelete(NULL);
        },
        "wake_word_encode",
        4096,
        this,
        5, // Higher priority for real-time encoding
        wake_word_encode_task_stack_,
        wake_word_encode_task_buffer_
    );

    if (encode_task_handle_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
    }
}

void AfeWakeWord::EncodeTask()
{
    // Initialize Opus encoder with low complexity settings
    OpusEncoder *encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
    if (encoder == nullptr) {
        ESP_LOGE(TAG, "Failed to create Opus encoder");
        return;
    }

    // Configure encoder for low complexity and real-time performance
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));          // Lowest complexity
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(16000));         // 16 kbps
    opus_encoder_ctl(encoder, OPUS_SET_VBR(0));                 // CBR for predictable performance
    opus_encoder_ctl(encoder, OPUS_SET_DTX(0));                 // Disable DTX for consistent processing
    opus_encoder_ctl(encoder, OPUS_SET_INBAND_FEC(0));          // Disable FEC to reduce overhead

    const size_t frame_size = 512;  // 32ms at 16kHz (matches typical chunk size)
    const size_t max_packet_size = 1276; // Maximum Opus packet size

    std::vector<uint8_t> encoded_packet(max_packet_size);

    ESP_LOGI(TAG, "Wake word encode task started");

    while (true) {
        std::vector<int16_t> pcm_frame;
        {
            std::unique_lock<std::mutex> lock(wake_word_mutex_);

            // Wait for PCM data to be available
            wake_word_cv_.wait(lock, [this]() {
                return !wake_word_pcm_.empty() || !running_;
            });

            if (!running_ && wake_word_pcm_.empty()) {
                break;
            }

            if (!wake_word_pcm_.empty()) {
                pcm_frame = std::move(wake_word_pcm_.front());
                wake_word_pcm_.pop_front();
            }
        }

        if (!pcm_frame.empty()) {
            // Ensure we have the correct frame size
            if (pcm_frame.size() != frame_size) {
                pcm_frame.resize(frame_size, 0); // Pad with zeros if needed
            }

            // Encode the PCM frame to Opus
            int encoded_bytes = opus_encode(encoder, pcm_frame.data(), frame_size, 
                                          encoded_packet.data(), max_packet_size);

            if (encoded_bytes > 0) {
                // Store the encoded Opus packet
                std::unique_lock<std::mutex> lock(wake_word_mutex_);
                wake_word_opus_.emplace_back(std::vector<uint8_t>(encoded_packet.begin(), 
                                                                encoded_packet.begin() + encoded_bytes));

                // Notify waiting consumers
                wake_word_cv_.notify_one();

                // Limit buffer size to prevent memory issues
                if (wake_word_opus_.size() > 100) { // Keep ~3 seconds of encoded data
                    wake_word_opus_.pop_front();
                }
            } else {
                ESP_LOGW(TAG, "Opus encoding failed with error: %d", encoded_bytes);
            }
        }

        // Small delay to prevent starving other tasks
        vTaskDelay(1);
    }

    // Cleanup
    opus_encoder_destroy(encoder);
    ESP_LOGI(TAG, "Wake word encode task stopped");
}

void CustomWakeWord::ParseWakenetModelConfig()
{
    if (models_ == nullptr) {
        ESP_LOGE(TAG, "Models list is null, cannot parse config");
        return;
    }

    // Get the index.json file from the model
    const char* index_json = esp_srmodel_get_buffer(models_, "index.json");
    if (index_json == nullptr) {
        ESP_LOGE(TAG, "Failed to get index.json from model");
        return;
    }

    // Parse JSON
    cJSON* root = cJSON_Parse(index_json);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        return;
    }

    // Parse language
    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = std::string(language_item->valuestring);
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    }

    // Parse duration
    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Parsed duration: %d", duration_);
    }

    // Parse threshold
    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = (float)threshold_item->valuedouble;
        ESP_LOGI(TAG, "Parsed threshold: %f", threshold_);
    }

    // Parse commands
    cJSON* commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array != nullptr && cJSON_IsArray(commands_array)) {
        commands_.clear();
        int commands_count = cJSON_GetArraySize(commands_array);
        for (int i = 0; i < commands_count; i++) {
            cJSON* command_item = cJSON_GetArrayItem(commands_array, i);
            if (command_item != nullptr) {
                cJSON* command_str = cJSON_GetObjectItem(command_item, "command");
                cJSON* text_str = cJSON_GetObjectItem(command_item, "text");
                cJSON* action_str = cJSON_GetObjectItem(command_item, "action");

                if (command_str != nullptr && cJSON_IsString(command_str)) {
                    WakeWordCommand cmd;
                    cmd.command = std::string(command_str->valuestring);

                    if (text_str != nullptr && cJSON_IsString(text_str)) {
                        cmd.text = std::string(text_str->valuestring);
                    } else {
                        cmd.text = cmd.command;
                    }

                    if (action_str != nullptr && cJSON_IsString(action_str)) {
                        cmd.action = std::string(action_str->valuestring);
                    } else {
                        cmd.action = "wake";
                    }

                    commands_.push_back(cmd);
                    ESP_LOGI(TAG, "Parsed command: %s, text: %s, action: %s", 
                             cmd.command.c_str(), cmd.text.c_str(), cmd.action.c_str());
                }
            }
        }
    }

    cJSON_Delete(root);
}

bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    codec_ = codec;
    commands_.clear();

    if (models_list == nullptr)
    {
        language_ = "cn";
        models_ = esp_srmodel_init("model");
#ifdef CONFIG_CUSTOM_WAKE_WORD
        threshold_ = CONFIG_CUSTOM_WAKE_WORD_THRESHOLD / 100.0f;
        commands_.push_back({CONFIG_CUSTOM_WAKE_WORD, CONFIG_CUSTOM_WAKE_WORD_DISPLAY, "wake"});
#endif
    }
    else
    {
        models_ = models_list;
        ParseWakenetModelConfig();
    }

    if (models_ == nullptr || models_->num == -1)
    {
        ESP_LOGE(TAG, "Failed to initialize wakenet model");
        return false;
    }

    // 初始化 multinet (命令词识别)
    mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, language_.c_str());
    if (mn_name_ == nullptr)
    {
        ESP_LOGW(TAG, "Language '%s' multinet not found, falling back to any multinet model", language_.c_str());
        mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, NULL);
    }
    if (mn_name_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to initialize multinet, mn_name is nullptr");
        ESP_LOGI(TAG, "Please refer to https://pcn7cs20v8cr.feishu.cn/wiki/CpQjwQsCJiQSWSkYEvrcxcbVnwh to add custom wake word");
        return false;
    }

    multinet_ = esp_mn_handle_from_name(mn_name_);
    if (multinet_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to get multinet handle from name: %s", mn_name_);
        return false;
    }

    // Initialize multinet model data
    multinet_model_data_ = multinet_->create(mn_name_);
    if (multinet_model_data_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Set detection threshold if configured
    if (threshold_ > 0)
    {
        multinet_->set_det_threshold(multinet_model_data_, threshold_);
    }

    ESP_LOGI(TAG, "Custom wake word initialized successfully with model: %s", mn_name_);
    return true;
}

void CustomWakeWord::Feed(const std::vector<int16_t> &data)
{
    if (!running_ || multinet_model_data_ == nullptr || data.empty())
    {
        return;
    }

    std::vector<int16_t> mono_data;
    const int16_t *input_data = data.data();
    size_t input_size = data.size();

    // Handle stereo to mono conversion if needed (assuming interleaved stereo)
    // If stereo (2 channels), extract left channel
    if (input_size % 2 == 0 && input_size > 1)
    {
        // Assume stereo input, extract left channel
        mono_data.reserve(input_size / 2);
        for (size_t i = 0; i < input_size; i += 2)
        {
            mono_data.push_back(input_data[i]);
        }
        input_data = mono_data.data();
        input_size = mono_data.size();
    }

    size_t chunk_size = multinet_->get_samp_chunksize(multinet_model_data_);

    // Process data in chunks
    for (size_t i = 0; i < input_size; i += chunk_size)
    {
        if (!running_)
        {
            break;
        }

        size_t current_chunk_size = std::min(chunk_size, input_size - i);

        // Run wake word detection
        esp_mn_state_t *state = multinet_->detect(multinet_model_data_, 
                                                  const_cast<int16_t*>(input_data + i));

        if (state->is_waked && state->command_id > 0)
        {
            // Valid wake word detected
            int command_index = state->command_id - 1;
            if (command_index < commands_.size())
            {
                const std::string wake_word = commands_[command_index].text;

                // Store wake word data for encoding
                std::vector<int16_t> wake_data(input_data + i, input_data + i + current_chunk_size);
                StoreWakeWordData(wake_data);

                // Encode stored wake word data
                EncodeWakeWordData();

                // Trigger callback if registered
                if (wake_word_detected_callback_)
                {
                    wake_word_detected_callback_(wake_word);
                }

                // Stop processing until reactivated
                running_ = false;
                break;
            }
        }
        else
        {
            // No wake word detected, just store data for potential future detection
            std::vector<int16_t> chunk_data(input_data + i, input_data + i + current_chunk_size);
            StoreWakeWordData(chunk_data);
        }
    }
}

void CustomWakeWord::EncodeWakeWordData()
{
    // Check if we already have a task running or no PCM data to encode
    if (wake_word_encode_task_stack_ != nullptr || wake_word_pcm_.empty()) {
        return;
    }

    // Allocate memory for task stack (4KB should be sufficient)
    wake_word_encode_task_stack_ = static_cast<uint8_t*>(heap_caps_malloc(4096, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
    if (wake_word_encode_task_stack_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for wake word encode task stack");
        return;
    }

    // Allocate memory for encoding buffer (suitable for Opus encoded frames)
    wake_word_encode_task_buffer_ = static_cast<uint8_t*>(heap_caps_malloc(4096, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
    if (wake_word_encode_task_buffer_ == nullptr) {
        ESP_LOGE(TAG, "Failed to allocate memory for wake word encode task buffer");
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
        return;
    }

    // Create a lambda function for the encoding task
    auto encode_task = [](void* arg) {
        CustomWakeWord* instance = static_cast<CustomWakeWord*>(arg);

        // Initialize Opus encoder with low complexity settings
        OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
        if (encoder == nullptr) {
            ESP_LOGE(TAG, "Failed to create Opus encoder");
            instance->CleanUpEncodeTaskResources();
            vTaskDelete(nullptr);
            return;
        }

        // Set low complexity encoding
        opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
        opus_encoder_ctl(encoder, OPUS_SET_BITRATE(OPUS_AUTO));

        // Process all PCM segments
        {
            std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);
            for (const auto& pcm_segment : instance->wake_word_pcm_) {
                // Encode the PCM segment
                int frame_size = pcm_segment.size();
                if (frame_size > 0) {
                    int max_data_bytes = 4096; // Size of our buffer
                    int encoded_bytes = opus_encode(encoder, 
                                                  pcm_segment.data(), 
                                                  frame_size, 
                                                  instance->wake_word_encode_task_buffer_, 
                                                  max_data_bytes);

                    if (encoded_bytes > 0) {
                        // Store encoded data
                        std::vector<uint8_t> opus_frame(instance->wake_word_encode_task_buffer_, 
                                                       instance->wake_word_encode_task_buffer_ + encoded_bytes);
                        instance->wake_word_opus_.push_back(opus_frame);
                    } else {
                        ESP_LOGW(TAG, "Opus encoding failed with error: %d", encoded_bytes);
                    }
                }
            }
        }

        // Add termination marker (empty Opus frame to indicate end of stream)
        std::vector<uint8_t> termination_marker;
        {
            std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);
            instance->wake_word_opus_.push_back(termination_marker);
        }

        // Signal that encoding is complete and data is available
        instance->wake_word_cv_.notify_all();

        // Cleanup
        opus_encoder_destroy(encoder);
        instance->CleanUpEncodeTaskResources();

        vTaskDelete(nullptr);
    };

    // Create the encoding task
    BaseType_t result = xTaskCreatePinnedToCore(
        reinterpret_cast<TaskFunction_t>(encode_task),
        "WakeWordEncodeTask",
        4096,
        this,
        5,  // Priority
        nullptr,
        1   // Core ID
    );

    if (result != pdPASS) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
    }
}

// Helper function to clean up task resources (should be added to the class)
void CustomWakeWord::CleanUpEncodeTaskResources()
{
    if (wake_word_encode_task_stack_ != nullptr) {
        heap_caps_free(wake_word_encode_task_stack_);
        wake_word_encode_task_stack_ = nullptr;
    }

    if (wake_word_encode_task_buffer_ != nullptr) {
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
    }
}

