std::string Board::GenerateUuid()
{
    uint8_t uuid[16];

    // Generate 16 random bytes using ESP32 hardware random number generator
    for (int i = 0; i < 16; i++) {
        uuid[i] = esp_random() & 0xFF;
    }

    // Set the version to 4 (UUIDv4)
    uuid[6] = (uuid[6] & 0x0F) | 0x40;  // 0100xxxx

    // Set the variant to RFC 4122 (bit 6 = 1, bit 7 = 0)
    uuid[8] = (uuid[8] & 0x3F) | 0x80;  // 10xxxxxx

    // Format as hexadecimal string with hyphens
    char uuid_str[37];  // 36 characters + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             uuid[0], uuid[1], uuid[2], uuid[3],
             uuid[4], uuid[5],
             uuid[6], uuid[7],
             uuid[8], uuid[9],
             uuid[10], uuid[11], uuid[12], uuid[13], uuid[14], uuid[15]);

    return std::string(uuid_str);
}

std::string Board::GetSystemInfoJson()
{
    SystemInfo system_info;

    // Get chip information
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    // Get MAC address
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char mac_str[18];
    snprintf(mac_str, sizeof(mac_str), "%02x:%02x:%02x:%02x:%02x:%02x",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);

    // Get flash size
    uint32_t flash_size = 0;
    esp_flash_get_size(NULL, &flash_size);

    // Get PSRAM size
    size_t psram_size = 0;
#ifdef CONFIG_SPIRAM
    psram_size = esp_psram_get_size();
#endif

    // Get minimum free heap size
    size_t minimum_free_heap_size = esp_get_minimum_free_heap_size();

    // Get running partition info
    const esp_partition_t* running_partition = esp_ota_get_running_partition();
    const char* partition_label = running_partition ? running_partition->label : "unknown";

    // Get chip model name
    const char* chip_model_name = "unknown";
    switch (chip_info.model) {
        case CHIP_ESP32:
            chip_model_name = "esp32";
            break;
        case CHIP_ESP32S2:
            chip_model_name = "esp32s2";
            break;
        case CHIP_ESP32S3:
            chip_model_name = "esp32s3";
            break;
        case CHIP_ESP32C3:
            chip_model_name = "esp32c3";
            break;
        case CHIP_ESP32C6:
            chip_model_name = "esp32c6";
            break;
        case CHIP_ESP32H2:
            chip_model_name = "esp32h2";
            break;
        default:
            chip_model_name = "unknown";
            break;
    }

    // Build JSON string
    char json_buffer[2048];
    snprintf(json_buffer, sizeof(json_buffer),
        "{"
        "\"version\":2,"
        "\"flash_size\":%u,"
        "\"psram_size\":%u,"
        "\"minimum_free_heap_size\":%u,"
        "\"mac_address\":\"%s\","
        "\"uuid\":\"%s\","
        "\"sku\":\"%s\","
        "\"chip_model_name\":\"%s\","
        "\"chip_info\":{"
            "\"model\":%d,"
            "\"cores\":%d,"
            "\"revision\":%d,"
            "\"features\":%u"
        "},"
        "\"partition\":{"
            "\"label\":\"%s\","
            "\"address\":%u,"
            "\"size\":%u"
        "},"
        "\"app\":{"
            "\"name\":\"xiaozhi\","
            "\"version\":\"%s\","
            "\"compile_time\":\"%s\""
        "}"
        "}",
        flash_size,
        psram_size,
        minimum_free_heap_size,
        mac_str,
        uuid_.c_str(),
        BOARD_NAME,
        chip_model_name,
        chip_info.model,
        chip_info.cores,
        chip_info.revision,
        chip_info.features,
        partition_label,
        running_partition ? running_partition->address : 0,
        running_partition ? running_partition->size : 0,
        system_info.GetAppVersion().c_str(),
        __DATE__ " " __TIME__
    );

    return std::string(json_buffer);
}

Esp32Camera::Esp32Camera(const esp_video_init_config_t &config)
{
    // Initialize member variables
    video_fd_ = -1;
    streaming_on_ = false;
    sensor_format_ = 0;
    sensor_width_ = 0;
    sensor_height_ = 0;
    frame_ = {};

    // Find and open the video device
    char device_path[32] = {0};
    bool device_found = false;

#if CONFIG_XIAOZHI_ENABLE_CAMERA_DEBUG_MODE
    log_available_video_devices();
#endif

    // Try to find the video device
    for (int i = 0; i < 10; i++) {
        snprintf(device_path, sizeof(device_path), "/dev/video%d", i);
        video_fd_ = open(device_path, O_RDWR);
        if (video_fd_ >= 0) {
            device_found = true;
            ESP_LOGI(TAG, "Opened video device: %s", device_path);
            break;
        }
    }

    if (!device_found) {
        ESP_LOGE(TAG, "No video device found");
        return;
    }

    // Query device capabilities
    struct v4l2_capability cap = {};
    if (ioctl(video_fd_, VIDIOC_QUERYCAP, &cap) != 0) {
        ESP_LOGE(TAG, "VIDIOC_QUERYCAP failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Check if this is a video capture device
    if (!(cap.capabilities & V4L2_CAP_VIDEO_CAPTURE)) {
        ESP_LOGE(TAG, "Device does not support video capture");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Check if device supports streaming I/O
    if (!(cap.capabilities & V4L2_CAP_STREAMING)) {
        ESP_LOGE(TAG, "Device does not support streaming I/O");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "Video device capabilities: driver='%s', card='%s', bus_info='%s', version=0x%08x, capabilities=0x%08x",
             cap.driver, cap.card, cap.bus_info, cap.version, cap.capabilities);

    // Try to set the format
    struct v4l2_format fmt = {};
    fmt.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    fmt.fmt.pix.width = config.resolution.width;
    fmt.fmt.pix.height = config.resolution.height;
    fmt.fmt.pix.pixelformat = config.format;
    fmt.fmt.pix.field = V4L2_FIELD_ANY;

    CAM_PRINT_FOURCC(config.format);

    if (ioctl(video_fd_, VIDIOC_S_FMT, &fmt) != 0) {
        ESP_LOGW(TAG, "VIDIOC_S_FMT failed, trying to get current format");
        // If setting format fails, try to get current format
        fmt.fmt.pix.width = 0;
        fmt.fmt.pix.height = 0;
        fmt.fmt.pix.pixelformat = 0;
        if (ioctl(video_fd_, VIDIOC_G_FMT, &fmt) != 0) {
            ESP_LOGE(TAG, "VIDIOC_G_FMT also failed");
            close(video_fd_);
            video_fd_ = -1;
            return;
        }
    }

    // Store the actual format used
    sensor_format_ = fmt.fmt.pix.pixelformat;
    sensor_width_ = fmt.fmt.pix.width;
    sensor_height_ = fmt.fmt.pix.height;
    frame_.width = sensor_width_;
    frame_.height = sensor_height_;

    ESP_LOGI(TAG, "Set format: width=%d, height=%d, pixelformat=0x%08lx", 
             sensor_width_, sensor_height_, sensor_format_);
    CAM_PRINT_FOURCC(sensor_format_);

    // Request buffers
    struct v4l2_requestbuffers req = {};
    req.count = 3;
    req.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    req.memory = V4L2_MEMORY_MMAP;

    if (ioctl(video_fd_, VIDIOC_REQBUFS, &req) != 0) {
        ESP_LOGE(TAG, "VIDIOC_REQBUFS failed");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    if (req.count < 2) {
        ESP_LOGE(TAG, "Insufficient buffer memory on device");
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    // Allocate buffer structures
    mmap_buffers_.resize(req.count);

    // Map the buffers
    for (size_t i = 0; i < req.count; i++) {
        struct v4l2_buffer buf = {};
        buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
        buf.memory = V4L2_MEMORY_MMAP;
        buf.index = i;

        if (ioctl(video_fd_, VIDIOC_QUERYBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QUERYBUF failed for buffer %d", (int)i);
            // Cleanup previously mapped buffers
            for (size_t j = 0; j < i; j++) {
                if (mmap_buffers_[j].start) {
                    munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
                }
            }
            mmap_buffers_.clear();
            close(video_fd_);
            video_fd_ = -1;
            return;
        }

        mmap_buffers_[i].length = buf.length;
        mmap_buffers_[i].start = mmap(nullptr, buf.length, PROT_READ | PROT_WRITE, MAP_SHARED, video_fd_, buf.m.offset);

        if (mmap_buffers_[i].start == MAP_FAILED) {
            ESP_LOGE(TAG, "mmap failed for buffer %d", (int)i);
            // Cleanup previously mapped buffers
            for (size_t j = 0; j < i; j++) {
                if (mmap_buffers_[j].start) {
                    munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
                }
            }
            mmap_buffers_.clear();
            close(video_fd_);
            video_fd_ = -1;
            return;
        }

        // Queue the buffer
        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0) {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed for buffer %d", (int)i);
            // Cleanup all mapped buffers
            for (size_t j = 0; j <= i; j++) {
                if (mmap_buffers_[j].start) {
                    munmap(mmap_buffers_[j].start, mmap_buffers_[j].length);
                }
            }
            mmap_buffers_.clear();
            close(video_fd_);
            video_fd_ = -1;
            return;
        }
    }

    // Start streaming
    int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    if (ioctl(video_fd_, VIDIOC_STREAMON, &type) != 0) {
        ESP_LOGE(TAG, "VIDIOC_STREAMON failed");
        // Cleanup mapped buffers
        for (auto &b : mmap_buffers_) {
            if (b.start) {
                munmap(b.start, b.length);
            }
        }
        mmap_buffers_.clear();
        close(video_fd_);
        video_fd_ = -1;
        return;
    }

    streaming_on_ = true;
    ESP_LOGI(TAG, "Camera initialized successfully");
}

bool Esp32Camera::Capture()
{
    if (video_fd_ < 0 || !streaming_on_)
    {
        ESP_LOGE(TAG, "Camera is not initialized or streaming is not enabled");
        return false;
    }

    // Wait for any previous encoding thread to finish
    if (encoder_thread_.joinable())
    {
        encoder_thread_.join();
    }

    struct v4l2_buffer buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;

    // Dequeue buffer - this will block until a frame is available
    if (ioctl(video_fd_, VIDIOC_DQBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_DQBUF failed, errno=%d(%s)", errno, strerror(errno));
        return false;
    }

    if (buf.index >= mmap_buffers_.size())
    {
        ESP_LOGE(TAG, "Invalid buffer index received: %u", buf.index);
        // Re-queue the buffer before returning
        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
        {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed during error handling");
        }
        return false;
    }

    // Free previous frame data if allocated
    if (frame_.data && frame_.allocated)
    {
        heap_caps_free(frame_.data);
        frame_.data = nullptr;
        frame_.len = 0;
        frame_.allocated = false;
    }

    uint8_t *src_data = static_cast<uint8_t *>(mmap_buffers_[buf.index].start);
    size_t src_len = buf.bytesused;

#ifdef CONFIG_XIAOZHI_ENABLE_ROTATE_CAMERA_IMAGE
    // When rotation is enabled, we need to process the image
    if (IMAGE_ROTATION_ANGLE == 90 || IMAGE_ROTATION_ANGLE == 270)
    {
        // For 90/270 degree rotation, width and height are swapped
        uint16_t rotated_width = frame_.height;
        uint16_t rotated_height = frame_.width;

        // Allocate memory for rotated image in PSRAM
        uint8_t *rotated_data = static_cast<uint8_t *>(
            heap_caps_malloc(src_len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));

        if (rotated_data == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate %zu bytes for rotated image in PSRAM", src_len);
            // Re-queue the buffer before returning
            if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
            {
                ESP_LOGE(TAG, "VIDIOC_QBUF failed during error handling");
            }
            return false;
        }

#ifdef CONFIG_IDF_TARGET_ESP32P4
        // Use PPA hardware acceleration for rotation
        ppa_srm_config_t config = {};
        config.input_width = sensor_width_;
        config.input_height = sensor_height_;
        config.rotation_angle = IMAGE_ROTATION_ANGLE;
        config.pixel_format = static_cast<ppa_pixel_format_t>(sensor_format_);

        esp_err_t ret = ppa_srm_process(&config, src_data, rotated_data);
        if (ret != ESP_OK)
        {
            ESP_LOGE(TAG, "PPA rotation failed: %s", esp_err_to_name(ret));
            heap_caps_free(rotated_data);
            // Re-queue the buffer before returning
            if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
            {
                ESP_LOGE(TAG, "VIDIOC_QBUF failed during error handling");
            }
            return false;
        }
#else
        // Software rotation
        esp_err_t ret = esp_imgfx_rotate_run(
            src_data, rotated_data, sensor_width_, sensor_height_,
            static_cast<v4l2_pix_fmt_t>(sensor_format_), IMAGE_ROTATION_ANGLE);
        if (ret != ESP_OK)
        {
            ESP_LOGE(TAG, "Software rotation failed: %s", esp_err_to_name(ret));
            heap_caps_free(rotated_data);
            // Re-queue the buffer before returning
            if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
            {
                ESP_LOGE(TAG, "VIDIOC_QBUF failed during error handling");
            }
            return false;
        }
#endif

        frame_.data = rotated_data;
        frame_.len = src_len;
        frame_.width = rotated_width;
        frame_.height = rotated_height;
        frame_.format = static_cast<v4l2_pix_fmt_t>(sensor_format_);
        frame_.allocated = true;
    }
    else
    {
        // No rotation needed or unsupported rotation angle
        // Make a copy of the data in PSRAM
        uint8_t *copied_data = static_cast<uint8_t *>(
            heap_caps_malloc(src_len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));

        if (copied_data == nullptr)
        {
            ESP_LOGE(TAG, "Failed to allocate %zu bytes for frame copy in PSRAM", src_len);
            // Re-queue the buffer before returning
            if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
            {
                ESP_LOGE(TAG, "VIDIOC_QBUF failed during error handling");
            }
            return false;
        }

        memcpy(copied_data, src_data, src_len);
        frame_.data = copied_data;
        frame_.len = src_len;
        frame_.width = frame_.width;
        frame_.height = frame_.height;
        frame_.format = static_cast<v4l2_pix_fmt_t>(sensor_format_);
        frame_.allocated = true;
    }
#else
    // No rotation - make a copy of the data in PSRAM
    uint8_t *copied_data = static_cast<uint8_t *>(
        heap_caps_malloc(src_len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));

    if (copied_data == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate %zu bytes for frame copy in PSRAM", src_len);
        // Re-queue the buffer before returning
        if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
        {
            ESP_LOGE(TAG, "VIDIOC_QBUF failed during error handling");
        }
        return false;
    }

    memcpy(copied_data, src_data, src_len);
    frame_.data = copied_data;
    frame_.len = src_len;
    frame_.format = static_cast<v4l2_pix_fmt_t>(sensor_format_);
    frame_.allocated = true;
#endif

    // Re-queue the buffer for capture
    if (ioctl(video_fd_, VIDIOC_QBUF, &buf) != 0)
    {
        ESP_LOGE(TAG, "VIDIOC_QBUF failed");
        // If we failed to re-queue, we should free our allocated memory
        if (frame_.allocated && frame_.data)
        {
            heap_caps_free(frame_.data);
            frame_.data = nullptr;
            frame_.len = 0;
            frame_.allocated = false;
        }
        return false;
    }

    ESP_LOGD(TAG, "Captured frame: %ux%u, format=0x%08lx, size=%zu bytes", 
             frame_.width, frame_.height, static_cast<unsigned long>(frame_.format), frame_.len);

    return true;
}

std::string Esp32Camera::Explain(const std::string &question)
{
    if (explain_url_.empty())
    {
        throw std::runtime_error("Image explain URL or token is not set");
    }

    if (!streaming_on_ || video_fd_ < 0)
    {
        throw std::runtime_error("Camera is not initialized or streaming is not active");
    }

    // Capture current frame first
    if (!Capture())
    {
        throw std::runtime_error("Failed to capture image from camera");
    }

    if (frame_.data == nullptr || frame_.len == 0)
    {
        throw std::runtime_error("No image data captured");
    }

    // Create local JPEG queue, 40 entries is about to store 512 * 40 = 20480 bytes of JPEG data
    QueueHandle_t jpeg_queue = xQueueCreate(40, sizeof(JpegChunk));
    if (jpeg_queue == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create JPEG queue");
        throw std::runtime_error("Failed to create JPEG queue");
    }

    // We spawn a thread to encode the image to JPEG using optimized encoder (cost about 500ms and 8KB SRAM)
    encoder_thread_ = std::thread([this, jpeg_queue]()
                                  {
        uint16_t w = frame_.width ? frame_.width : 320;
        uint16_t h = frame_.height ? frame_.height : 240;
        v4l2_pix_fmt_t enc_fmt = frame_.format;
        bool ok = image_to_jpeg_cb(
            frame_.data, frame_.len, w, h, enc_fmt, 80,
            [](void* arg, size_t index, const void* data, size_t len) -> size_t {
                auto jpeg_queue = static_cast<QueueHandle_t>(arg);
                JpegChunk chunk = {.data = nullptr, .len = len};
                if (index == 0 && data != nullptr && len > 0) {
                    chunk.data = (uint8_t*)heap_caps_aligned_alloc(16, len, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT);
                    if (chunk.data == nullptr) {
                        ESP_LOGE(TAG, "Failed to allocate %zu bytes for JPEG chunk", len);
                        chunk.len = 0;
                    } else {
                        memcpy(chunk.data, data, len);
                    }
                } else {
                    chunk.len = 0;  // Sentinel or error
                }
                xQueueSend(jpeg_queue, &chunk, portMAX_DELAY);
                return len;
            },
            jpeg_queue);

        if (!ok) {
            JpegChunk chunk = {.data = nullptr, .len = 0};
            xQueueSend(jpeg_queue, &chunk, portMAX_DELAY);
        } });

    auto network = Board::GetInstance().GetNetwork();
    auto http = network->CreateHttp(3);
    // Construct multipart/form-data request body
    std::string boundary = "----ESP32_CAMERA_BOUNDARY";

    // Configure HTTP client, use chunked transfer encoding
    http->SetHeader("Device-Id", SystemInfo::GetMacAddress().c_str());
    http->SetHeader("Client-Id", Board::GetInstance().GetUuid().c_str());
    if (!explain_token_.empty())
    {
        http->SetHeader("Authorization", "Bearer " + explain_token_);
    }
    http->SetHeader("Content-Type", "multipart/form-data; boundary=" + boundary);
    http->SetHeader("Transfer-Encoding", "chunked");
    if (!http->Open("POST", explain_url_))
    {
        ESP_LOGE(TAG, "Failed to connect to explain URL");
        // Clear the queue
        encoder_thread_.join();
        JpegChunk chunk;
        while (xQueueReceive(jpeg_queue, &chunk, portMAX_DELAY) == pdPASS)
        {
            if (chunk.data != nullptr)
            {
                heap_caps_free(chunk.data);
            }
            else
            {
                break;
            }
        }
        vQueueDelete(jpeg_queue);
        throw std::runtime_error("Failed to connect to explain URL");
    }

    {
        // First part: question field
        std::string question_field;
        question_field += "--" + boundary + "\r\n";
        question_field += "Content-Disposition: form-data; name=\"question\"\r\n";
        question_field += "\r\n";
        question_field += question + "\r\n";
        http->Write(question_field.c_str(), question_field.size());
    }
    {
        // Second part: file field header
        std::string file_header;
        file_header += "--" + boundary + "\r\n";
        file_header += "Content-Disposition: form-data; name=\"file\"; filename=\"camera.jpg\"\r\n";
        file_header += "Content-Type: image/jpeg\r\n";
        file_header += "\r\n";
        http->Write(file_header.c_str(), file_header.size());
    }

    // Third part: JPEG data
    size_t total_sent = 0;
    bool saw_terminator = false;
    while (true)
    {
        JpegChunk chunk;
        if (xQueueReceive(jpeg_queue, &chunk, portMAX_DELAY) != pdPASS)
        {
            ESP_LOGE(TAG, "Failed to receive JPEG chunk");
            break;
        }
        if (chunk.data == nullptr)
        {
            saw_terminator = true;
            break; // The last chunk
        }
        http->Write((const char *)chunk.data, chunk.len);
        total_sent += chunk.len;
        heap_caps_free(chunk.data);
    }
    // Wait for the encoder thread to finish
    encoder_thread_.join();
    // Clean up queue
    vQueueDelete(jpeg_queue);

    if (!saw_terminator || total_sent == 0)
    {
        ESP_LOGE(TAG, "JPEG encoder failed or produced empty output");
        throw std::runtime_error("Failed to encode image to JPEG");
    }

    {
        // Fourth part: multipart footer
        std::string multipart_footer;
        multipart_footer += "\r\n--" + boundary + "--\r\n";
        http->Write(multipart_footer.c_str(), multipart_footer.size());
    }
    // End block
    http->Write("", 0);

    if (http->GetStatusCode() != 200)
    {
        ESP_LOGE(TAG, "Failed to upload photo, status code: %d", http->GetStatusCode());
        throw std::runtime_error("Failed to upload photo");
    }

    std::string result = http->ReadAll();
    http->Close();

    // Get remain task stack size
    size_t remain_stack_size = uxTaskGetStackHighWaterMark(nullptr);
    ESP_LOGI(TAG, "Explain image size=%d bytes, compressed size=%d, remain stack size=%d, question=%s\n%s",
             (int)frame_.len, (int)total_sent, (int)remain_stack_size, question.c_str(), result.c_str());
    return result;
}

void WifiBoard::StartNetwork()
{
    auto &wifi_manager = WifiManager::GetInstance();

    // Initialize WiFi manager with board-specific settings
    wifi_manager.SetApSsidPrefix("XiaoZhi-");
    wifi_manager.SetLanguage(Lang::GetCurrentLanguage());

    // Set up unified event callback for all WiFi events
    wifi_manager.SetEventCallback([this](NetworkEvent event, const std::string &data) {
        this->OnNetworkEvent(event, data);
    });

    // Attempt to connect to WiFi or enter config mode
    TryWifiConnect();
}

void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data)
{
    switch (event)
    {
    case NetworkEvent::Scanning:
        ESP_LOGI(TAG, "Scanning for networks");
        break;

    case NetworkEvent::Connecting:
        ESP_LOGI(TAG, "Connecting to SSID: %s", data.c_str());
        // Stop the connection timeout timer as we're now connecting
        esp_timer_stop(connect_timer_);
        break;

    case NetworkEvent::Connected:
        ESP_LOGI(TAG, "WiFi connected to SSID: %s", data.c_str());
        // Stop the connection timeout timer
        esp_timer_stop(connect_timer_);

        // No longer in config mode
        in_config_mode_ = false;

        // Release provisioning resources if we were in config mode
        if (WifiManager::GetInstance().IsConfigMode())
        {
            WifiManager::GetInstance().StopConfigAp();
        }

        // Update device state
        Application::GetInstance().SetDeviceState(kDeviceStateIdle);
        break;

    case NetworkEvent::Disconnected:
        ESP_LOGI(TAG, "WiFi disconnected");
        // If we were in config mode, stay in config mode
        // Otherwise, we might want to try reconnecting
        if (!in_config_mode_)
        {
            // Could trigger a reconnection attempt here if needed
        }
        break;

    case NetworkEvent::WifiConfigModeEnter:
        ESP_LOGI(TAG, "Entered WiFi config mode");
        in_config_mode_ = true;
        Application::GetInstance().SetDeviceState(kDeviceStateWifiConfiguring);
        break;

    case NetworkEvent::WifiConfigModeExit:
        ESP_LOGI(TAG, "Exited WiFi config mode");
        in_config_mode_ = false;

        // Stop any ongoing connection attempt
        esp_timer_stop(connect_timer_);

        // Try to connect again after exiting config mode
        TryWifiConnect();

        // Update device state
        Application::GetInstance().SetDeviceState(kDeviceStateIdle);
        break;
    }

    // Notify external callback if set
    if (network_event_callback_)
    {
        network_event_callback_(event, data);
    }
}

void WifiBoard::StartWifiConfigMode()
{
    ESP_LOGI(TAG, "Entering WiFi configuration mode");

    // Set device state to configuring
    Application::GetInstance().SetDeviceState(kDeviceStateConfiguring);

    // Show notification about entering config mode
    GetDisplay()->ShowNotification(Lang::Strings::WIFI_CONFIG_MODE_ACTIVE);

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Bluetooth Low Energy provisioning via Blufi
    ESP_LOGI(TAG, "Starting Blufi provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::BLUFI_PROVISIONING_STARTED);
    Blufi::GetInstance().init();
    WifiManager::GetInstance().StartBlufiConfig();
#elif defined(CONFIG_USE_ACOUSTIC_WIFI_PROVISIONING)
    // Acoustic provisioning through audio input
    ESP_LOGI(TAG, "Starting acoustic provisioning");
    GetDisplay()->ShowNotification(Lang::Strings::ACOUSTIC_PROVISIONING_STARTED);
    // Start AFSK demodulator for acoustic provisioning
    AfskDemod::GetInstance().Start();
    WifiManager::GetInstance().StartAcousticConfig();
#else
    // Default hotspot-based configuration
    ESP_LOGI(TAG, "Starting hotspot-based configuration");
    GetDisplay()->ShowNotification(Lang::Strings::HOTSPOT_CONFIG_STARTED);
    WifiManager::GetInstance().StartAccessPoint();
#endif
}

void WifiBoard::EnterWifiConfigMode()
{
    // Check if we're already in config mode to prevent conflicts
    if (IsInWifiConfigMode()) {
        ESP_LOGW(TAG, "Already in WiFi config mode");
        return;
    }

    ESP_LOGI(TAG, "Entering WiFi config mode");

    // Gracefully shut down any active network connections
    auto& wifi_manager = WifiManager::GetInstance();

    // Stop any ongoing station connection attempts
    if (wifi_manager.IsStationActive()) {
        wifi_manager.StopStation();
    }

    // Stop the connection timeout timer if running
    if (connect_timer_) {
        esp_timer_stop(connect_timer_);
    }

    // Reset any active audio/communication processes
    // Stop AFSK demodulation if active
    AfskDemod::GetInstance().Stop();

#ifdef CONFIG_USE_ESP_BLUFI_WIFI_PROVISIONING
    // Make sure Blufi is properly deinitialized
    Blufi::GetInstance().deinit();
#endif

    // Display notification about entering config mode
    Application::GetInstance().Alert(
        Lang::Strings::WIFI_CONFIG_MODE, 
        Lang::Strings::WIFI_CONFIG_MODE_DESC, 
        "gear", 
        Lang::Sounds::OGG_WIFICONFIG
    );

    // Give some time for the alert to be displayed
    vTaskDelay(pdMS_TO_TICKS(500));

    // Start the WiFi configuration mode
    StartWifiConfigMode();
}

std::string WifiBoard::GetDeviceStatusJson()
{
    std::string json = "{";

    // Add audio speaker volume
    auto& settings = Settings::GetInstance();
    json += "\"speaker_volume\":" + std::to_string(settings.GetSpeakerVolume()) + ",";

    // Add display brightness and theme
    json += "\"screen_brightness\":" + std::to_string(settings.GetScreenBrightness()) + ",";
    json += "\"screen_theme\":\"" + std::string(settings.GetScreenTheme()) + "\",";

    // Add battery information
    auto& system_info = SystemInfo::GetInstance();
    json += "\"battery_level\":" + std::to_string(system_info.GetBatteryLevel()) + ",";
    json += "\"is_charging\":" + std::string(system_info.IsCharging() ? "true" : "false") + ",";

    // Add WiFi network details
    auto& wifi = WifiManager::GetInstance();
    if (!wifi.IsConfigMode() && wifi.IsConnected()) {
        json += "\"wifi_ssid\":\"" + wifi.GetSsid() + "\",";
        json += "\"wifi_rssi\":" + std::to_string(wifi.GetRssi()) + ",";
    } else {
        json += "\"wifi_ssid\":\"\",";
        json += "\"wifi_rssi\":0,";
    }

    // Add chip temperature
    json += "\"chip_temperature\":" + std::to_string(system_info.GetChipTemperature());

    json += "}";

    return json;
}

void LcdDisplay::InitializeLcdThemes()
{
    auto& theme_manager = LvglThemeManager::GetInstance();

    // Create light theme
    auto light_theme = std::make_unique<LvglTheme>("light");

    // Basic colors for light theme
    light_theme->set_background_color(lv_color_hex(0xFFFFFF)); // White background
    light_theme->set_text_color(lv_color_hex(0x000000));       // Black text
    light_theme->set_border_color(lv_color_hex(0xDDDDDD));     // Light gray border

    // Chat bubble colors for light theme
    light_theme->set_user_bubble_color(lv_color_hex(0xE3F2FD));      // Light blue for user
    light_theme->set_assistant_bubble_color(lv_color_hex(0xF5F5F5)); // Light gray for assistant
    light_theme->set_system_bubble_color(lv_color_hex(0xEEEEEE));    // Lighter gray for system
    light_theme->set_system_text_color(lv_color_hex(0x666666));      // Dark gray for system text
    light_theme->set_chat_background_color(lv_color_hex(0xFAFAFA));  // Slightly off-white chat background

    // Low battery warning color
    light_theme->set_low_battery_color(lv_color_hex(0xFF5252)); // Red for warning

    // Set fonts for light theme
    light_theme->set_text_font(&BUILTIN_TEXT_FONT);
    light_theme->set_icon_font(&BUILTIN_ICON_FONT);
    light_theme->set_large_icon_font(&font_awesome_30_4);

    // Spacing configuration
    light_theme->set_spacing([](int level) -> int {
        switch(level) {
            case 1: return 4;
            case 2: return 8;
            case 4: return 16;
            default: return level * 4;
        }
    });

    // Register light theme
    theme_manager.RegisterTheme(std::move(light_theme));

    // Create dark theme
    auto dark_theme = std::make_unique<LvglTheme>("dark");

    // Basic colors for dark theme
    dark_theme->set_background_color(lv_color_hex(0x121212)); // Dark background
    dark_theme->set_text_color(lv_color_hex(0xFFFFFF));       // White text
    dark_theme->set_border_color(lv_color_hex(0x333333));     // Dark gray border

    // Chat bubble colors for dark theme
    dark_theme->set_user_bubble_color(lv_color_hex(0x1976D2));       // Blue for user
    dark_theme->set_assistant_bubble_color(lv_color_hex(0x424242));  // Dark gray for assistant
    dark_theme->set_system_bubble_color(lv_color_hex(0x333333));     // Even darker gray for system
    dark_theme->set_system_text_color(lv_color_hex(0xBBBBBB));       // Light gray for system text
    dark_theme->set_chat_background_color(lv_color_hex(0x1E1E1E));   // Dark chat background

    // Low battery warning color
    dark_theme->set_low_battery_color(lv_color_hex(0xFF5252)); // Red for warning

    // Set fonts for dark theme
    dark_theme->set_text_font(&BUILTIN_TEXT_FONT);
    dark_theme->set_icon_font(&BUILTIN_ICON_FONT);
    dark_theme->set_large_icon_font(&font_awesome_30_4);

    // Spacing configuration (same as light theme)
    dark_theme->set_spacing([](int level) -> int {
        switch(level) {
            case 1: return 4;
            case 2: return 8;
            case 4: return 16;
            default: return level * 4;
        }
    });

    // Register dark theme
    theme_manager.RegisterTheme(std::move(dark_theme));
}

LcdDisplay::LcdDisplay(esp_lcd_panel_io_handle_t panel_io, esp_lcd_panel_handle_t panel, int width, int height)
    : panel_io_(panel_io)
    , panel_(panel)
    , width_(width)
    , height_(height)
    , display_(nullptr)
    , current_theme_(nullptr)
    , container_(nullptr)
    , top_bar_(nullptr)
    , status_bar_(nullptr)
    , content_(nullptr)
    , bottom_bar_(nullptr)
    , side_bar_(nullptr)
    , network_label_(nullptr)
    , status_label_(nullptr)
    , notification_label_(nullptr)
    , mute_label_(nullptr)
    , battery_label_(nullptr)
    , emoji_label_(nullptr)
    , emoji_image_(nullptr)
    , emoji_box_(nullptr)
    , chat_message_label_(nullptr)
    , preview_image_(nullptr)
    , low_battery_popup_(nullptr)
    , low_battery_label_(nullptr)
    , hide_subtitle_(false)
    , preview_timer_(nullptr)
{
    // Initialize the preview image timer
    esp_timer_create_args_t timer_args = {
        .callback = [](void* arg) {
            LcdDisplay* display = static_cast<LcdDisplay*>(arg);
            if (display->Lock(0)) {
                if (display->preview_image_ != nullptr) {
                    lv_obj_add_flag(display->preview_image_, LV_OBJ_FLAG_HIDDEN);
                }
                if (display->emoji_box_ != nullptr) {
                    lv_obj_remove_flag(display->emoji_box_, LV_OBJ_FLAG_HIDDEN);
                }
                if (display->gif_controller_) {
                    display->gif_controller_->Start();
                }
                display->Unlock();
            }
        },
        .arg = this,
        .dispatch_method = ESP_TIMER_TASK,
        .name = "preview_timer"
    };

    ESP_ERROR_CHECK(esp_timer_create(&timer_args, &preview_timer_));
}

SpiLcdDisplay::SpiLcdDisplay(esp_lcd_panel_io_handle_t panel_io, esp_lcd_panel_handle_t panel,
                             int width, int height, int offset_x, int offset_y, bool mirror_x, bool mirror_y, bool swap_xy)
    : LcdDisplay(panel_io, panel, width, height)
{

    // draw white
    std::vector<uint16_t> buffer(width_, 0xFFFF);
    for (int y = 0; y < height_; y++)
    {
        esp_lcd_panel_draw_bitmap(panel_, 0, y, width_, y + 1, buffer.data());
    }

    // Set the display to on
    ESP_LOGI(TAG, "Turning display on");
    {
        esp_err_t __err = esp_lcd_panel_disp_on_off(panel_, true);
        if (__err == ESP_ERR_NOT_SUPPORTED)
        {
            ESP_LOGW(TAG, "Panel does not support disp_on_off; assuming ON");
        }
        else
        {
            ESP_ERROR_CHECK(__err);
        }
    }

    ESP_LOGI(TAG, "Initialize LVGL library");
    lv_init();

    ESP_LOGI(TAG, "Initialize LVGL port");
    lvgl_port_cfg_t port_cfg = ESP_LVGL_PORT_INIT_CONFIG();
    port_cfg.task_priority = 1;
    port_cfg.timer_period_ms = 50;
    lvgl_port_init(&port_cfg);

    ESP_LOGI(TAG, "Adding LCD display");
    const lvgl_port_display_cfg_t display_cfg = {
        .io_handle = panel_io_,
        .panel_handle = panel_,
        .buffer_size = static_cast<uint32_t>(width_ * 20),
        .double_buffer = true,
        .hres = static_cast<uint32_t>(width_),
        .vres = static_cast<uint32_t>(height_),
        .rotation = {
            .swap_xy = swap_xy,
            .mirror_x = mirror_x,
            .mirror_y = mirror_y,
        },
        .flags = {
            .buff_dma = 1,
            .swap_bytes = 0,
            .full_refresh = 1,
            .direct_mode = 1,
        },
    };

    const lvgl_port_display_rgb_cfg_t rgb_cfg = {
        .flags = {
            .bb_mode = true,
            .avoid_tearing = true,
        }};

    display_ = lvgl_port_add_disp_rgb(&display_cfg, &rgb_cfg);
    if (display_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to add RGB display");
        return;
    }

    if (offset_x != 0 || offset_y != 0)
    {
        lv_display_set_offset(display_, offset_x, offset_y);
    }

    SetupUI();
}

