void LcdDisplay::SetChatMessage(const char *role, const char *content)
{
    DisplayLockGuard lock(this);

    // Don't display empty messages
    if (content == nullptr || strlen(content) == 0)
    {
        return;
    }

    // Hide AI logo when showing non-system messages
    if (emoji_label_ != nullptr && (role == nullptr || strcmp(role, "system") != 0))
    {
        lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
    }

    // Create a new message bubble
    lv_obj_t *bubble_container = lv_obj_create(content_);
    lv_obj_set_style_radius(bubble_container, 8, 0);
    lv_obj_set_style_pad_all(bubble_container, 12, 0);
    lv_obj_set_style_border_width(bubble_container, 1, 0);
    lv_obj_set_scrollbar_mode(bubble_container, LV_SCROLLBAR_MODE_OFF);

    auto lvgl_theme = static_cast<LvglTheme *>(current_theme_);

    // Determine bubble styling based on role
    if (role != nullptr && strcmp(role, "user") == 0)
    {
        // User message - right aligned
        lv_obj_set_style_bg_color(bubble_container, lvgl_theme->user_bubble_color(), 0);
        lv_obj_set_style_border_color(bubble_container, lvgl_theme->border_color(), 0);
        lv_obj_set_style_base_dir(bubble_container, LV_BASE_DIR_RTL, 0);
        lv_obj_set_user_data(bubble_container, (void *)"user");
    }
    else if (role != nullptr && strcmp(role, "system") == 0)
    {
        // System message - centered with different styling
        lv_obj_set_style_bg_color(bubble_container, lvgl_theme->system_bubble_color(), 0);
        lv_obj_set_style_border_color(bubble_container, lvgl_theme->border_color(), 0);
        lv_obj_set_style_base_dir(bubble_container, LV_BASE_DIR_LTR, 0);
        lv_obj_set_user_data(bubble_container, (void *)"system");
    }
    else
    {
        // Assistant/AI message - left aligned (default)
        lv_obj_set_style_bg_color(bubble_container, lvgl_theme->assistant_bubble_color(), 0);
        lv_obj_set_style_border_color(bubble_container, lvgl_theme->border_color(), 0);
        lv_obj_set_style_base_dir(bubble_container, LV_BASE_DIR_LTR, 0);
        lv_obj_set_user_data(bubble_container, (void *)"assistant");
    }

    // Create label for message content
    lv_obj_t *message_label = lv_label_create(bubble_container);
    lv_label_set_text(message_label, content);
    lv_obj_set_style_text_color(message_label, lvgl_theme->text_color(), 0);
    lv_obj_set_style_text_font(message_label, lvgl_theme->text_font()->font(), 0);
    lv_label_set_long_mode(message_label, LV_LABEL_LONG_WRAP);
    lv_obj_set_width(message_label, LV_HOR_RES * 0.7); // Limit width to 70% of screen

    // Position based on role
    if (role != nullptr && strcmp(role, "user") == 0)
    {
        // Right align for user messages
        lv_obj_align(bubble_container, LV_ALIGN_RIGHT_MID, 0, 0);
    }
    else if (role != nullptr && strcmp(role, "system") == 0)
    {
        // Center for system messages
        lv_obj_align(bubble_container, LV_ALIGN_CENTER, 0, 0);
    }
    else
    {
        // Left align for assistant messages
        lv_obj_align(bubble_container, LV_ALIGN_LEFT_MID, 0, 0);
    }

    // Manage message history - remove oldest messages if we exceed MAX_MESSAGES
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    if (child_count > MAX_MESSAGES)
    {
        // Remove the oldest message (first child)
        lv_obj_t *oldest_message = lv_obj_get_child(content_, 0);
        if (oldest_message != nullptr)
        {
            lv_obj_del(oldest_message);
        }
    }

    // Scroll to show the new message
    lv_obj_scroll_to_view_recursive(bubble_container, LV_ANIM_ON);
}

void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image)
{
    DisplayLockGuard lock(this);

    // Stop any existing preview timer
    esp_timer_stop(preview_timer_);

    if (image == nullptr) {
        // Clear preview - show emoji box again
        if (emoji_box_ != nullptr) {
            lv_obj_remove_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
        }

        // Hide preview image if it exists
        if (preview_image_ != nullptr) {
            lv_obj_add_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
        }

        // Clear cached image
        preview_image_cached_.reset();

        // Restart GIF animation if it was stopped
        if (gif_controller_) {
            gif_controller_->Start();
        }

        return;
    }

    // Store the new image
    preview_image_cached_ = std::move(image);

    // If we don't have a preview image object, we can't display it
    if (preview_image_ == nullptr) {
        ESP_LOGE(TAG, "Preview image object is not initialized");
        return;
    }

    auto img_dsc = preview_image_cached_->image_dsc();
    if (img_dsc == nullptr) {
        ESP_LOGE(TAG, "Invalid image descriptor");
        return;
    }

    // Set the image source
    lv_image_set_src(preview_image_, img_dsc);

    // Scale the image appropriately
    if (img_dsc->header.w > 0 && img_dsc->header.h > 0) {
        // Calculate scale to fit within reasonable bounds
        lv_coord_t max_width = LV_HOR_RES * 85 / 100;  // 85% of screen width
        lv_coord_t max_height = LV_VER_RES * 85 / 100; // 85% of screen height

        float scale_x = (float)max_width / img_dsc->header.w;
        float scale_y = (float)max_height / img_dsc->header.h;
        float scale = std::min(scale_x, scale_y);

        // Convert to LVGL scale format (256 = 100%)
        uint16_t lv_scale = (uint16_t)(scale * 256);
        if (lv_scale == 0) lv_scale = 256; // Fallback to 100%

        lv_image_set_scale(preview_image_, lv_scale);
    }

    // Stop any running GIF animation
    if (gif_controller_) {
        gif_controller_->Stop();
    }

    // Hide emoji box and show preview image
    if (emoji_box_ != nullptr) {
        lv_obj_add_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
    }

    if (preview_image_ != nullptr) {
        lv_obj_remove_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
    }

    // Start timer to automatically hide the preview after duration
    ESP_ERROR_CHECK(esp_timer_start_once(preview_timer_, PREVIEW_IMAGE_DURATION_MS * 1000));
}

