void LcdDisplay::SetEmotion(const char *emotion)
{
    // Stop any running GIF animation
    if (gif_controller_)
    {
        DisplayLockGuard lock(this);
        gif_controller_->Stop();
        gif_controller_.reset();
    }

    if (emoji_image_ == nullptr)
    {
        return;
    }

    auto emoji_collection = static_cast<LvglTheme *>(current_theme_)->emoji_collection();
    auto image = emoji_collection != nullptr ? emoji_collection->GetEmojiImage(emotion) : nullptr;
    if (image == nullptr)
    {
        const char *utf8 = font_awesome_get_utf8(emotion);
        if (utf8 != nullptr && emoji_label_ != nullptr)
        {
            DisplayLockGuard lock(this);
            lv_label_set_text(emoji_label_, utf8);
            lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
            lv_obj_remove_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
        }
        return;
    }

    DisplayLockGuard lock(this);
    if (image->IsGif())
    {
        // Create new GIF controller
        gif_controller_ = std::make_unique<LvglGif>(image->image_dsc());

        if (gif_controller_->IsLoaded())
        {
            // Set up frame update callback
            gif_controller_->SetFrameCallback([this]()
                                              { lv_image_set_src(emoji_image_, gif_controller_->image_dsc()); });

            // Set initial frame and start animation
            lv_image_set_src(emoji_image_, gif_controller_->image_dsc());
            gif_controller_->Start();

            // Show GIF, hide others
            lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
            lv_obj_remove_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
        }
        else
        {
            ESP_LOGE(TAG, "Failed to load GIF for emotion: %s", emotion);
            gif_controller_.reset();
        }
    }
    else
    {
        lv_image_set_src(emoji_image_, image->image_dsc());
        lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
        lv_obj_remove_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
    }

#if CONFIG_USE_WECHAT_MESSAGE_STYLE
    // In WeChat message style, if emotion is neutral, don't display it
    if (strcmp(emotion, "neutral") == 0)
    {
        // Stop GIF animation if running
        if (gif_controller_)
        {
            gif_controller_->Stop();
            gif_controller_.reset();
        }

        lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
        lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
    }
#endif
}

void LcdDisplay::SetTheme(Theme *theme)
{
    if (theme == nullptr) {
        return;
    }

    DisplayLockGuard lock(this);

    // Update the current theme
    current_theme_ = theme;

    // Get theme properties
    auto lvgl_theme = static_cast<LvglTheme *>(current_theme_);
    auto text_font = lvgl_theme->text_font()->font();
    auto icon_font = lvgl_theme->icon_font()->font();

    // Update screen styles
    auto screen = lv_screen_active();
    lv_obj_set_style_text_font(screen, text_font, 0);
    lv_obj_set_style_text_color(screen, lvgl_theme->text_color(), 0);
    lv_obj_set_style_bg_color(screen, lvgl_theme->background_color(), 0);

    // Update container styles
    if (container_ != nullptr) {
        lv_obj_set_style_bg_color(container_, lvgl_theme->background_color(), 0);
        lv_obj_set_style_border_color(container_, lvgl_theme->border_color(), 0);
    }

    // Update top bar styles
    if (top_bar_ != nullptr) {
        lv_obj_set_style_bg_color(top_bar_, lvgl_theme->background_color(), 0);
        lv_obj_set_style_text_color(top_bar_, lvgl_theme->text_color(), 0);
    }

    // Update status bar styles
    if (status_bar_ != nullptr) {
        lv_obj_set_style_text_color(status_bar_, lvgl_theme->text_color(), 0);
    }

    // Update icon labels
    if (network_label_ != nullptr) {
        lv_obj_set_style_text_font(network_label_, icon_font, 0);
        lv_obj_set_style_text_color(network_label_, lvgl_theme->text_color(), 0);
    }

    if (mute_label_ != nullptr) {
        lv_obj_set_style_text_font(mute_label_, icon_font, 0);
        lv_obj_set_style_text_color(mute_label_, lvgl_theme->text_color(), 0);
    }

    if (battery_label_ != nullptr) {
        lv_obj_set_style_text_font(battery_label_, icon_font, 0);
        lv_obj_set_style_text_color(battery_label_, lvgl_theme->text_color(), 0);
    }

    // Update status labels
    if (notification_label_ != nullptr) {
        lv_obj_set_style_text_color(notification_label_, lvgl_theme->text_color(), 0);
    }

    if (status_label_ != nullptr) {
        lv_obj_set_style_text_color(status_label_, lvgl_theme->text_color(), 0);
        lv_label_set_text(status_label_, lv_label_get_text(status_label_));
    }

#if CONFIG_USE_WECHAT_MESSAGE_STYLE
    // Update chat content area
    if (content_ != nullptr) {
        lv_obj_set_style_bg_color(content_, lvgl_theme->chat_background_color(), 0);
    }

    // Update existing chat messages
    if (content_ != nullptr) {
        uint32_t child_count = lv_obj_get_child_cnt(content_);
        for (uint32_t i = 0; i < child_count; i++) {
            lv_obj_t *container = lv_obj_get_child(content_, i);
            if (container != nullptr && lv_obj_get_child_cnt(container) > 0) {
                lv_obj_t *bubble = lv_obj_get_child(container, 0);
                if (bubble != nullptr) {
                    void *bubble_type_ptr = lv_obj_get_user_data(bubble);
                    if (bubble_type_ptr != nullptr) {
                        const char *bubble_type = (const char *)bubble_type_ptr;
                        if (strcmp(bubble_type, "user") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->user_bubble_color(), 0);
                            lv_obj_t *text = lv_obj_get_child(bubble, 0);
                            if (text != nullptr) {
                                lv_obj_set_style_text_color(text, lvgl_theme->text_color(), 0);
                            }
                        } else if (strcmp(bubble_type, "assistant") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->assistant_bubble_color(), 0);
                            lv_obj_t *text = lv_obj_get_child(bubble, 0);
                            if (text != nullptr) {
                                lv_obj_set_style_text_color(text, lvgl_theme->text_color(), 0);
                            }
                        } else if (strcmp(bubble_type, "system") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->system_bubble_color(), 0);
                            lv_obj_t *text = lv_obj_get_child(bubble, 0);
                            if (text != nullptr) {
                                lv_obj_set_style_text_color(text, lvgl_theme->system_text_color(), 0);
                            }
                        } else if (strcmp(bubble_type, "image") == 0) {
                            lv_obj_set_style_bg_color(bubble, lvgl_theme->assistant_bubble_color(), 0);
                        }
                    }
                }
            }
        }
    }

    // Update emoji elements
    if (emoji_label_ != nullptr) {
        lv_obj_set_style_text_color(emoji_label_, lvgl_theme->text_color(), 0);
    }
#else
    // Update bottom bar styles
    if (bottom_bar_ != nullptr) {
        lv_obj_set_style_bg_color(bottom_bar_, lvgl_theme->background_color(), 0);
        lv_obj_set_style_text_color(bottom_bar_, lvgl_theme->text_color(), 0);
    }

    // Update chat message label
    if (chat_message_label_ != nullptr) {
        lv_obj_set_style_text_color(chat_message_label_, lvgl_theme->text_color(), 0);
    }

    // Update emoji box and label
    if (emoji_box_ != nullptr) {
        lv_obj_set_style_text_color(emoji_box_, lvgl_theme->text_color(), 0);
    }

    if (emoji_label_ != nullptr) {
        lv_obj_set_style_text_color(emoji_label_, lvgl_theme->text_color(), 0);
    }
#endif

    // Update low battery popup
    if (low_battery_popup_ != nullptr) {
        lv_obj_set_style_bg_color(low_battery_popup_, lvgl_theme->low_battery_color(), 0);
    }

    if (low_battery_label_ != nullptr) {
        lv_obj_set_style_text_color(low_battery_label_, lv_color_white(), 0);
    }

    // Save theme to settings
    Settings settings("display", false);
    settings.SetString("theme", theme->name());
    settings.Save();
}

SingleLed::SingleLed(gpio_num_t gpio)
{
    // Configure LED strip with WS2812 settings
    led_strip_config_t strip_config = {};
    strip_config.strip_gpio_num = gpio;
    strip_config.max_leds = 1;  // Single LED
    strip_config.led_pixel_format = LED_PIXEL_FORMAT_GRB;
    strip_config.led_model = LED_MODEL_WS2812;
    strip_config.flags.invert_out = false;

    // Configure RMT for LED strip
    led_strip_rmt_config_t rmt_config = {};
    rmt_config.clk_src = RMT_CLK_SRC_DEFAULT;
    rmt_config.resolution_hz = 10 * 1000 * 1000;  // 10MHz
    rmt_config.flags.with_dma = false;

    // Install LED strip driver
    led_strip_new_rmt_device(&strip_config, &rmt_config, &led_strip_);

    // Initialize color values
    r_ = 0;
    g_ = 0;
    b_ = 0;

    // Clear the LED initially
    if (led_strip_ != nullptr) {
        led_strip_clear(led_strip_);
    }

    // Initialize blink counter and interval
    blink_counter_ = 0;
    blink_interval_ms_ = 0;

    // Create blink timer
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = [](void* arg) {
        static_cast<SingleLed*>(arg)->OnBlinkTimer();
    };
    timer_args.arg = this;
    timer_args.name = "blink_timer";
    esp_timer_create(&timer_args, &blink_timer_);
}

void SingleLed::OnStateChanged()
{
    auto &app = Application::GetInstance();
    auto device_state = app.GetDeviceState();
    switch (device_state)
    {
    case kDeviceStateStarting:
        SetColor(0, 0, DEFAULT_BRIGHTNESS);
        StartContinuousBlink(100);
        break;
    case kDeviceStateWifiConfiguring:
        SetColor(0, 0, DEFAULT_BRIGHTNESS);
        StartContinuousBlink(100);
        break;
    case kDeviceStateIdle:
        SetColor(0, DEFAULT_BRIGHTNESS, 0); // Green
        TurnOn();
        break;
    case kDeviceStateConnecting:
        SetColor(DEFAULT_BRIGHTNESS, DEFAULT_BRIGHTNESS, 0); // Yellow
        StartContinuousBlink(500);
        break;
    case kDeviceStateListening:
        SetColor(DEFAULT_BRIGHTNESS, 0, DEFAULT_BRIGHTNESS); // Magenta
        StartContinuousBlink(200);
        break;
    case kDeviceStateSpeaking:
        SetColor(0, DEFAULT_BRIGHTNESS, 0); // Bright green
        TurnOn();
        break;
    case kDeviceStateUpgrading:
        SetColor(HIGH_BRIGHTNESS, HIGH_BRIGHTNESS, 0); // Bright yellow
        StartContinuousBlink(100);
        break;
    case kDeviceStateActivating:
        SetColor(0, 0, HIGH_BRIGHTNESS); // Bright blue
        StartContinuousBlink(300);
        break;
    default:
        SetColor(LOW_BRIGHTNESS, 0, 0); // Dim red for unknown/error state
        TurnOn();
        break;
    }
}

MqttProtocol::MqttProtocol()
{
    alive_ = std::make_shared<bool>(true);
    event_group_handle_ = xEventGroupCreate();
    reconnect_timer_ = nullptr;
    udp_ = nullptr;
    mqtt_ = nullptr;
    local_sequence_ = 0;
    remote_sequence_ = 0;
    server_sample_rate_ = 16000;
    server_frame_duration_ = OPUS_FRAME_DURATION_MS;
    error_occurred_ = false;

    // Initialize reconnect timer
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = [](void* arg) {
        auto protocol = static_cast<MqttProtocol*>(arg);
        auto alive = protocol->alive_;  // Capture alive flag

        Application::GetInstance().Schedule([protocol, alive]() {
            if (*alive) {
                protocol->StartMqttClient(false);
            }
        });
    };
    timer_args.arg = this;
    timer_args.name = "mqtt_reconnect";

    esp_timer_create(&timer_args, &reconnect_timer_);
}

bool MqttProtocol::StartMqttClient(bool report_error)
{
    if (mqtt_ != nullptr)
    {
        ESP_LOGW(TAG, "Mqtt client already started");
        mqtt_.reset();
    }

    Settings settings("mqtt", false);
    auto endpoint = settings.GetString("endpoint");
    auto client_id = settings.GetString("client_id");
    auto username = settings.GetString("username");
    auto password = settings.GetString("password");
    int keepalive_interval = settings.GetInt("keepalive", 240);
    publish_topic_ = settings.GetString("publish_topic");

    if (endpoint.empty() || client_id.empty())
    {
        ESP_LOGE(TAG, "MQTT endpoint or client_id is empty");
        if (report_error)
        {
            SetError(Lang::Strings::INVALID_CONFIG);
        }
        return false;
    }

    auto network = Board::GetInstance().GetNetwork();
    mqtt_ = network->CreateMqtt();

    if (mqtt_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create MQTT client");
        if (report_error)
        {
            SetError(Lang::Strings::SERVER_ERROR);
        }
        return false;
    }

    // Configure MQTT client
    mqtt_->SetClientId(client_id);
    mqtt_->SetEndpoint(endpoint);
    if (!username.empty())
    {
        mqtt_->SetUsername(username);
    }
    if (!password.empty())
    {
        mqtt_->SetPassword(password);
    }
    mqtt_->SetKeepAlive(keepalive_interval);

    // Set up event handlers
    mqtt_->OnConnect([this]()
    {
        ESP_LOGI(TAG, "MQTT connected");
        xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_CONNECTED_EVENT);

        // Subscribe to necessary topics
        Settings settings("mqtt", false);
        auto subscribe_topic = settings.GetString("subscribe_topic");
        if (!subscribe_topic.empty())
        {
            mqtt_->Subscribe(subscribe_topic);
        }
    });

    mqtt_->OnDisconnect([this](int reason)
    {
        ESP_LOGW(TAG, "MQTT disconnected, reason: %d", reason);
        xEventGroupClearBits(event_group_handle_, MQTT_PROTOCOL_CONNECTED_EVENT);

        if (*alive_)
        {
            // Schedule reconnection
            esp_timer_start_once(reconnect_timer_, 5000000); // 5 seconds
        }
    });

    mqtt_->OnMessage([this](const std::string& topic, const std::string& payload)
    {
        ESP_LOGD(TAG, "MQTT message received, topic: %s", topic.c_str());

        cJSON* root = cJSON_Parse(payload.c_str());
        if (root == nullptr)
        {
            ESP_LOGE(TAG, "Failed to parse JSON payload: %s", payload.c_str());
            return;
        }

        auto type_item = cJSON_GetObjectItem(root, "type");
        if (type_item != nullptr && cJSON_IsString(type_item))
        {
            std::string type = type_item->valuestring;

            if (type == "hello")
            {
                ParseServerHello(root);
            }
            else if (type == "error")
            {
                auto error_item = cJSON_GetObjectItem(root, "message");
                if (error_item != nullptr && cJSON_IsString(error_item))
                {
                    ESP_LOGE(TAG, "Server error: %s", error_item->valuestring);
                    SetError(error_item->valuestring);
                }
            }
            // Handle other message types as needed
        }

        cJSON_Delete(root);
    });

    // Start the MQTT client
    if (!mqtt_->Start())
    {
        ESP_LOGE(TAG, "Failed to start MQTT client");
        mqtt_.reset();
        if (report_error)
        {
            SetError(Lang::Strings::SERVER_ERROR);
        }
        return false;
    }

    return true;
}

bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (packet == nullptr) {
        return false;
    }

    std::lock_guard<std::mutex> lock(channel_mutex_);
    if (udp_ == nullptr) {
        ESP_LOGE(TAG, "UDP channel is not opened");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Prepare the UDP packet header
    std::vector<uint8_t> udp_packet;
    udp_packet.reserve(sizeof(uint8_t) + sizeof(uint8_t) + sizeof(uint16_t) + 
                       sizeof(uint32_t) + sizeof(uint32_t) + sizeof(uint32_t) + 
                       packet->payload.size() + aes_nonce_.size());

    // Packet type: 0x01 for audio
    udp_packet.push_back(0x01);

    // Flags: 0x00
    udp_packet.push_back(0x00);

    // Payload length (network byte order)
    uint16_t payload_len = htons(packet->payload.size());
    uint8_t* len_ptr = reinterpret_cast<uint8_t*>(&payload_len);
    udp_packet.insert(udp_packet.end(), len_ptr, len_ptr + sizeof(uint16_t));

    // SSRC (using session_id hash or fixed value, using simple hash of session_id_)
    uint32_t ssrc = 0;
    for (char c : session_id_) {
        ssrc = ssrc * 31 + static_cast<uint32_t>(c);
    }
    if (ssrc == 0) ssrc = 0x12345678; // fallback SSRC
    uint32_t ssrc_nbo = htonl(ssrc);
    uint8_t* ssrc_ptr = reinterpret_cast<uint8_t*>(&ssrc_nbo);
    udp_packet.insert(udp_packet.end(), ssrc_ptr, ssrc_ptr + sizeof(uint32_t));

    // Timestamp (network byte order)
    uint32_t timestamp_nbo = htonl(packet->timestamp);
    uint8_t* ts_ptr = reinterpret_cast<uint8_t*>(&timestamp_nbo);
    udp_packet.insert(udp_packet.end(), ts_ptr, ts_ptr + sizeof(uint32_t));

    // Sequence number (network byte order)
    uint32_t sequence_nbo = htonl(local_sequence_);
    uint8_t* seq_ptr = reinterpret_cast<uint8_t*>(&sequence_nbo);
    udp_packet.insert(udp_packet.end(), seq_ptr, seq_ptr + sizeof(uint32_t));

    // Create nonce based on packet characteristics
    std::vector<uint8_t> nonce = aes_nonce_;
    if (nonce.size() >= 16) {
        // Update nonce with packet info (last 8 bytes)
        uint32_t seq_for_nonce = local_sequence_;
        uint32_t size_for_nonce = packet->payload.size();

        // Copy sequence and size into nonce
        memcpy(nonce.data() + 8, &seq_for_nonce, sizeof(seq_for_nonce));
        memcpy(nonce.data() + 12, &size_for_nonce, sizeof(size_for_nonce));
    }

    // Add nonce to the beginning of the packet
    udp_packet.insert(udp_packet.end(), nonce.begin(), nonce.end());

    // Encrypt the payload using AES-CTR
    size_t encrypted_size = packet->payload.size();
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};
    std::vector<uint8_t> encrypted_payload(encrypted_size);

    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, encrypted_size, &nc_off, 
                                   nonce.data(), stream_block,
                                   reinterpret_cast<const uint8_t*>(packet->payload.data()),
                                   encrypted_payload.data());

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Add encrypted payload to packet
    udp_packet.insert(udp_packet.end(), encrypted_payload.begin(), encrypted_payload.end());

    // Send the packet
    std::string data(reinterpret_cast<char*>(udp_packet.data()), udp_packet.size());
    if (!udp_->Send(data)) {
        ESP_LOGE(TAG, "Failed to send audio packet");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Update sequence number for next packet
    local_sequence_++;

    return true;
}

bool MqttProtocol::OpenAudioChannel()
{
    // Send hello message to request UDP channel
    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message))
    {
        ESP_LOGE(TAG, "Failed to send hello message");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Wait for server hello response
    EventBits_t bits = xEventGroupWaitBits(event_group_handle_,
                                         MQTT_PROTOCOL_SERVER_HELLO_EVENT,
                                         pdTRUE,  // Clear bits on exit
                                         pdFALSE, // Wait for any bit
                                         pdMS_TO_TICKS(MQTT_PROTOCOL_HANDSHAKE_TIMEOUT_MS));

    if ((bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT) == 0)
    {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        SetError(Lang::Strings::SERVER_TIMEOUT);
        return false;
    }

    // Create UDP connection
    auto network = Board::GetInstance().GetNetwork();
    udp_ = network->CreateUdp();
    if (udp_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create UDP socket");
        SetError(Lang::Strings::NETWORK_ERROR);
        return false;
    }

    // Connect to UDP server
    if (!udp_->Connect(udp_server_, udp_port_))
    {
        ESP_LOGE(TAG, "Failed to connect to UDP server %s:%d", udp_server_.c_str(), udp_port_);
        SetError(Lang::Strings::SERVER_NOT_CONNECTED);
        udp_.reset();
        return false;
    }

    // Set up UDP receive callback
    udp_->OnData([this](const uint8_t *data, size_t len)
    {
        if (len < aes_nonce_.size())
        {
            ESP_LOGE(TAG, "Received UDP packet too short: %d bytes", len);
            return;
        }

        // Extract header information
        std::string nonce((const char*)data, aes_nonce_.size());
        uint16_t payload_size = ntohs(*(uint16_t*)&nonce[2]);
        uint32_t timestamp = ntohl(*(uint32_t*)&nonce[8]);
        uint32_t sequence = ntohl(*(uint32_t*)&nonce[12]);

        // Validate packet size
        if (len != aes_nonce_.size() + payload_size)
        {
            ESP_LOGE(TAG, "Invalid packet size: expected %d, got %d", aes_nonce_.size() + payload_size, len);
            return;
        }

        // Check sequence number
        if (sequence <= remote_sequence_)
        {
            ESP_LOGW(TAG, "Duplicate or old packet received: %d <= %d", sequence, remote_sequence_);
            return;
        }
        remote_sequence_ = sequence;

        // Decrypt payload
        std::string decrypted;
        decrypted.resize(payload_size);

        size_t nc_off = 0;
        uint8_t stream_block[16] = {0};
        if (mbedtls_aes_crypt_ctr(&aes_ctx_, payload_size, &nc_off, 
                                (uint8_t *)nonce.c_str(), stream_block,
                                (uint8_t *)&data[aes_nonce_.size()], 
                                (uint8_t *)decrypted.data()) != 0)
        {
            ESP_LOGE(TAG, "Failed to decrypt audio packet");
            return;
        }

        // Create audio packet
        auto packet = std::make_unique<AudioStreamPacket>();
        packet->payload = std::move(decrypted);
        packet->timestamp = timestamp;
        packet->sequence = sequence;

        // Pass to callback if available
        if (on_incoming_audio_ != nullptr)
        {
            on_incoming_audio_(std::move(packet));
        }

        // Update last incoming time for timeout detection
        last_incoming_time_ = std::chrono::steady_clock::now();
    });

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

std::string MqttProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();
    cJSON_AddStringToObject(root, "type", "hello");

    // Add device capabilities
    cJSON *capabilities = cJSON_CreateObject();
    cJSON_AddBoolToObject(capabilities, "aec", Board::GetInstance().HasAecSupport());
    cJSON_AddBoolToObject(capabilities, "mcp", Board::GetInstance().HasMcpSupport());
    cJSON_AddItemToObject(root, "capabilities", capabilities);

    // Add audio parameters
    cJSON *audio_params = cJSON_CreateObject();
    cJSON_AddStringToObject(audio_params, "format", "opus");
    cJSON_AddNumberToObject(audio_params, "sample_rate", AUDIO_SAMPLE_RATE);
    cJSON_AddNumberToObject(audio_params, "frame_duration", AUDIO_FRAME_DURATION_MS);
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    // Add transport preference
    cJSON_AddStringToObject(root, "transport", "udp");

    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string);
    cJSON_free(json_string);
    cJSON_Delete(root);

    return result;
}

void MqttProtocol::ParseServerHello(const cJSON *root)
{
    cJSON *session_id = cJSON_GetObjectItem(root, "session_id");
    if (!cJSON_IsString(session_id)) {
        ESP_LOGE(TAG, "Session ID is missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    cJSON *udp_addr = cJSON_GetObjectItem(root, "udp_addr");
    if (!cJSON_IsString(udp_addr)) {
        ESP_LOGE(TAG, "UDP address is missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    cJSON *udp_port = cJSON_GetObjectItem(root, "udp_port");
    if (!cJSON_IsNumber(udp_port)) {
        ESP_LOGE(TAG, "UDP port is missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    cJSON *key = cJSON_GetObjectItem(root, "key");
    if (!cJSON_IsString(key)) {
        ESP_LOGE(TAG, "Encryption key is missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    cJSON *nonce = cJSON_GetObjectItem(root, "nonce");
    if (!cJSON_IsString(nonce)) {
        ESP_LOGE(TAG, "Nonce is missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    cJSON *audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (!cJSON_IsObject(audio_params)) {
        ESP_LOGE(TAG, "Audio parameters are missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    cJSON *sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
    if (!cJSON_IsNumber(sample_rate)) {
        ESP_LOGE(TAG, "Sample rate is missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    cJSON *frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
    if (!cJSON_IsNumber(frame_duration)) {
        ESP_LOGE(TAG, "Frame duration is missing or invalid");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    // Store session ID
    session_id_ = session_id->valuestring;

    // Store UDP connection parameters
    udp_server_ = udp_addr->valuestring;
    udp_port_ = udp_port->valueint;

    // Decode and store encryption key and nonce
    std::string key_hex = key->valuestring;
    std::string nonce_hex = nonce->valuestring;

    std::string decoded_key = DecodeHexString(key_hex);
    aes_nonce_ = DecodeHexString(nonce_hex);

    // Initialize AES context
    mbedtls_aes_init(&aes_ctx_);
    if (mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char*)decoded_key.data(), decoded_key.size() * 8) != 0) {
        ESP_LOGE(TAG, "Failed to set AES key");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    // Store audio parameters
    server_sample_rate_ = sample_rate->valueint;
    server_frame_duration_ = frame_duration->valueint;

    // Reset sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Signal that server hello has been processed
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);

    ESP_LOGI(TAG, "Server hello parsed successfully, session_id: %s", session_id_.c_str());
}

bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    if (packet->payload.empty())
    {
        return true; // Nothing to send
    }

    bool result = false;

    if (version_ == 2)
    {
        size_t packet_size = sizeof(BinaryProtocol2) + packet->payload.size();
        std::vector<uint8_t> buffer(packet_size);
        BinaryProtocol2* bp2 = reinterpret_cast<BinaryProtocol2*>(buffer.data());

        bp2->version = htons(2);
        bp2->type = htons(0); // Assuming 0 is the audio data type
        bp2->timestamp = htonl(packet->timestamp);
        bp2->payload_size = htonl(static_cast<uint32_t>(packet->payload.size()));

        memcpy(bp2->payload, packet->payload.data(), packet->payload.size());

        result = websocket_->SendBinary(reinterpret_cast<const char*>(buffer.data()), packet_size);
    }
    else if (version_ == 3)
    {
        size_t packet_size = sizeof(BinaryProtocol3) + packet->payload.size();
        std::vector<uint8_t> buffer(packet_size);
        BinaryProtocol3* bp3 = reinterpret_cast<BinaryProtocol3*>(buffer.data());

        bp3->type = 0; // Assuming 0 is the audio data type
        bp3->payload_size = htons(static_cast<uint16_t>(packet->payload.size()));

        memcpy(bp3->payload, packet->payload.data(), packet->payload.size());

        result = websocket_->SendBinary(reinterpret_cast<const char*>(buffer.data()), packet_size);
    }
    else
    {
        // For other versions, send raw payload
        result = websocket_->SendBinary(reinterpret_cast<const char*>(packet->payload.data()), packet->payload.size());
    }

    if (!result)
    {
        ESP_LOGE(TAG, "Failed to send audio data");
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

bool WebsocketProtocol::OpenAudioChannel()
{
    Settings settings("websocket", false);
    std::string url = settings.GetString("url");
    std::string token = settings.GetString("token");
    int version = settings.GetInt("version");
    if (version != 0)
    {
        version_ = version;
    }

    error_occurred_ = false;

    auto network = Board::GetInstance().GetNetwork();
    websocket_ = network->CreateWebSocket(1);
    if (websocket_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to create websocket");
        return false;
    }

    // Set authentication header
    if (!token.empty())
    {
        websocket_->SetHeader("Authorization", "Bearer " + token);
    }

    // Build handshake message
    cJSON *root = cJSON_CreateObject();
    cJSON *features = cJSON_CreateObject();

    cJSON_AddBoolToObject(features, "mcp", true);
    cJSON_AddItemToObject(root, "features", features);
    cJSON_AddStringToObject(root, "transport", "websocket");

    cJSON *audio_params = cJSON_CreateObject();
    cJSON_AddStringToObject(audio_params, "format", "opus");
    cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);
    cJSON_AddNumberToObject(audio_params, "channels", 1);
    cJSON_AddNumberToObject(audio_params, "frame_duration", OPUS_FRAME_DURATION_MS);
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    auto json_str = cJSON_PrintUnformatted(root);
    std::string message(json_str);
    cJSON_free(json_str);
    cJSON_Delete(root);

    // Set up data handler for incoming messages
    websocket_->SetDataHandler([this](const uint8_t* data, size_t len, bool is_binary) {
        if (is_binary) {
            // Handle binary audio packets according to protocol version
            if (version_ == 2 || version_ == 3) {
                // For v2 and v3 protocols
                if (len >= 4) {
                    // Extract payload length (first 4 bytes, big endian)
                    uint32_t payload_length = ntohl(*reinterpret_cast<const uint32_t*>(data));

                    // Check if we have enough data
                    if (len >= 4 + payload_length) {
                        // Extract the actual audio payload
                        const uint8_t* payload = data + 4;

                        // Create audio stream packet
                        auto packet = std::make_unique<AudioStreamPacket>();
                        packet->data.assign(payload, payload + payload_length);
                        packet->timestamp = Board::GetInstance().GetSystemTimeMs();

                        // Notify application about incoming audio packet
                        Application::GetInstance().OnAudioPacketReceived(std::move(packet));
                    }
                }
            } else {
                // Default handling for other versions - treat entire data as payload
                auto packet = std::make_unique<AudioStreamPacket>();
                packet->data.assign(data, data + len);
                packet->timestamp = Board::GetInstance().GetSystemTimeMs();

                Application::GetInstance().OnAudioPacketReceived(std::move(packet));
            }
        } else {
            // Handle text messages
            std::string text_message(reinterpret_cast<const char*>(data), len);
            ESP_LOGI(TAG, "Received text message: %s", text_message.c_str());

            // Parse JSON message
            cJSON *json = cJSON_Parse(text_message.c_str());
            if (json != nullptr) {
                auto type = cJSON_GetObjectItem(json, "type");
                if (type != nullptr && cJSON_IsString(type)) {
                    if (strcmp(type->valuestring, "hello") == 0) {
                        ParseServerHello(json);
                    }
                }
                cJSON_Delete(json);
            }
        }
    });

    // Connect to WebSocket server
    if (!websocket_->Connect(url)) {
        ESP_LOGE(TAG, "Failed to connect to websocket server: %s", url.c_str());
        websocket_.reset();
        return false;
    }

    // Send handshake message
    if (!websocket_->Send(message)) {
        ESP_LOGE(TAG, "Failed to send handshake message");
        websocket_.reset();
        return false;
    }

    ESP_LOGI(TAG, "Audio channel opened successfully");
    return true;
}

std::string WebsocketProtocol::GetHelloMessage()
{
    cJSON *root = cJSON_CreateObject();
    cJSON_AddStringToObject(root, "type", "hello");
    cJSON_AddNumberToObject(root, "version", version_);

    // Add features array
    cJSON *features = cJSON_CreateArray();
    cJSON_AddItemToArray(features, cJSON_CreateString("AEC"));
    cJSON_AddItemToArray(features, cJSON_CreateString("MCP"));
    cJSON_AddItemToObject(root, "features", features);

    // Add transport
    cJSON_AddStringToObject(root, "transport", "websocket");

    // Add audio parameters
    cJSON *audio_params = cJSON_CreateObject();
    cJSON_AddStringToObject(audio_params, "format", "PCM");
    cJSON_AddNumberToObject(audio_params, "sample_rate", 16000);
    cJSON_AddNumberToObject(audio_params, "channels", 1);
    cJSON_AddNumberToObject(audio_params, "frame_duration", 20);
    cJSON_AddItemToObject(root, "audio_params", audio_params);

    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string);
    cJSON_Delete(root);
    free(json_string);

    return result;
}

void WebsocketProtocol::ParseServerHello(const cJSON *root)
{
    // Validate transport type
    auto transport = cJSON_GetObjectItem(root, "transport");
    if (transport == nullptr || !cJSON_IsString(transport)) {
        ESP_LOGE(TAG, "Invalid or missing transport in server hello");
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    if (strcmp(transport->valuestring, "websocket") != 0) {
        ESP_LOGE(TAG, "Unsupported transport type: %s", transport->valuestring);
        SetError(Lang::Strings::SERVER_ERROR);
        return;
    }

    // Extract session identification
    auto session_id = cJSON_GetObjectItem(root, "session_id");
    if (session_id != nullptr && cJSON_IsString(session_id)) {
        session_id_ = session_id->valuestring;
        ESP_LOGI(TAG, "Session ID: %s", session_id_->c_str());
    }

    // Extract audio parameters
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (audio_params != nullptr && cJSON_IsObject(audio_params)) {
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (sample_rate != nullptr && cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valueint;
        }

        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (frame_duration != nullptr && cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valueint;
        }

        ESP_LOGI(TAG, "Server audio params - Sample rate: %d, Frame duration: %d", 
                 server_sample_rate_, server_frame_duration_);
    }

    // Set event flag to indicate successful server hello processing
    xEventGroupSetBits(event_group_handle_, WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT);
}
